// Extract message — FULL REPLACE v3 (adds audio detection + hasAudio)
// Input: $json.body.updates[0]
// Output: { text, chatId, login, hasFile, hasAudio, files[] }

function normalizeText(s) {
  return String(s || '').replace(/\u00A0/g, ' ').trim();
}

function toArrayMaybe(x) {
  if (!x) return [];
  if (Array.isArray(x)) return x;
  return [x];
}

function uniqPushFile(arr, f) {
  const kind = String(f.kind || '');
  const id = String(f.file_id || f.id || '');
  const key = `${kind}|${id}`;
  if (!id) return;
  if (arr._seen && arr._seen.has(key)) return;
  arr._seen = arr._seen || new Set();
  arr._seen.add(key);
  arr.push(f);
}

function guessKindByName(name) {
  const n = String(name || '').toLowerCase();
  if (/\.(png|jpg|jpeg|bmp|gif|tif|tiff|webp)$/i.test(n)) return 'image';
  if (/\.(ogg|opus|mp3|wav|m4a|aac|flac)$/i.test(n)) return 'audio';
  return 'file';
}

const update = $json?.body?.updates?.[0];
if (!update) return [];

const text = normalizeText(update.text || '') || 'Empty';

// chatId/login
const chatId = update?.from?.id ?? update?.chat?.id ?? null;
const login = update?.from?.login ?? null;

const files = [];

// images can come in different shapes: images[0] array, images array, or object
const imagesRaw = update.images;
if (imagesRaw) {
  // sometimes images is [[...]] or [...]
  const imgs = Array.isArray(imagesRaw) && Array.isArray(imagesRaw[0]) ? imagesRaw[0] : imagesRaw;
  for (const src of toArrayMaybe(imgs)) {
    if (!src) continue;
    const file_id = src.file_id || src.id;
    uniqPushFile(files, {
      kind: 'image',
      file_id,
      name: src.name || '',
      size: src.size,
      width: src.width,
      height: src.height,
    });
  }
}

// generic file (docs, logs, voice, etc)
if (update.file) {
  const f = update.file;
  const file_id = f.file_id || f.id;
  const name = f.name || '';
  const kind = guessKindByName(name);
  uniqPushFile(files, {
    kind,
    file_id,
    name,
    size: f.size,
  });
}

const hasFile = files.length > 0;
const hasAudio = files.some(f => String(f.kind).toLowerCase() === 'audio');

return [{
  json: {
    text,
    chatId,
    login,
    hasFile,
    hasAudio,
    files,
  }
}];

// Prepare reply — FULL REPLACE v2-B (LOGparser)
// - Always returns TXT file with final report
// - File name: "<archiveBase>.txt" (fallback logparser_report.txt)
// - Preserves chatId/login; sendText splitting handled by downstream If file + Send Text/Send file nodes

function s(x){ return x == null ? '' : String(x); }

function normalizeChatId(chatId) {
  if (!chatId) return null;
  const t = String(chatId).trim();
  return t.includes('/') ? t : `0/0/${t}`;
}

function extractAssistantText(j) {
  if (!j || typeof j !== 'object') return '';
  if (typeof j.message?.content === 'string') return j.message.content;
  if (typeof j.ollama?.message?.content === 'string') return j.ollama.message.content;
  if (typeof j.response === 'string') return j.response;
  if (typeof j.text === 'string') return j.text;
  return '';
}

function stripThink(raw) {
  return s(raw).replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
}

function baseName(name) {
  const t = s(name).trim();
  if (!t) return 'logparser_report';
  const just = t.split(/[\\/]/).pop();
  return just.replace(/\.(zip|tgz|tar\.gz|gz|tar|7z)$/i, '');
}

const base = $input.item.json || {};
const chatId = normalizeChatId(base.chatId || base.chat_id);
const login = base.login || base.user || null;

const content = stripThink(extractAssistantText(base)).trim() || stripThink(s(base.message?.content)).trim();
const fileBase = baseName(base.sourceFileName || base.archiveName || base.fileName || (Array.isArray(base.files) && base.files[0] && base.files[0].name) || '');
const outName = `${fileBase}.txt`;

// Add UTF-8 BOM (Excel-friendly if needed)
const bom = Buffer.from([0xEF,0xBB,0xBF]);
const buf = Buffer.concat([bom, Buffer.from(content || 'N/A', 'utf8')]);

return [{
  json: {
    ...base,
    chatId,
    login,
    fileName: outName,
    isFile: true,
  },
  binary: {
    file: {
      data: buf.toString('base64'),
      fileName: outName,
      mimeType: 'text/plain; charset=utf-8',
    }
  }
}];

// Code node "Stop"
// Ничего не делаем и останавливаем цепочку для этих сообщений
return [];

// Storage Structure Extract — FULL REPLACE v6.1-wf4225-cli-blocks-from-ulc (tmp evidence file, no big payload)
// Reads ULC combinedLogPath (already unpacked mega-log), extracts structure-related evidence for LLM2,
// writes a local temp snippet file, returns only the path + stats.
//
// Priority (same intent as WF4225):
//   1) CLI blocks: # show enclosures / # show redundancy-mode / # show versions detail
//   2) Fallback keyword windows (Midplane/EMP/Array/RedundancyMode/etc)

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const base = $input.item.json || {};
const s = (x) => (x == null ? '' : String(x));

const SRC = s(base.combinedLogPath).trim(); // ULC output (147MB+ is OK)
const TMP_ROOT = s($env.LOGPARSER_LLM_TMP_ROOT || '/home/node/.n8n/tmp/logparser_llm').trim() || '/home/node/.n8n/tmp/logparser_llm';
const TTL_HOURS = Number($env.LOGPARSER_LLM_TTL_HOURS || 72);

// If env is not set (or <=0) we DO NOT clip by chars. Set env to force clipping.
const MAX_CHARS = Number($env.STRUCTURE_EXTRACT_MAX_CHARS || 0);

// --- helpers ---
function fileExists(p){ try { return !!p && fs.existsSync(p) && fs.statSync(p).isFile(); } catch { return false; } }
function ensureDir(p){ try { fs.mkdirSync(p, { recursive:true }); } catch {} }

function cleanupOld(root, ttlHours){
  try {
    if (!fs.existsSync(root)) return;
    const now = Date.now();
    const ttlMs = Math.max(1, ttlHours) * 3600 * 1000;
    for (const name of fs.readdirSync(root)) {
      const p = path.join(root, name);
      let st;
      try { st = fs.statSync(p); } catch { continue; }
      if (!st.isDirectory()) continue;
      if ((now - Number(st.mtimeMs || 0)) > ttlMs) {
        try { fs.rmSync(p, { recursive:true, force:true }); } catch {}
      }
    }
  } catch {}
}

function safeBaseName(name){
  const t = s(name).trim();
  if (!t) return 'archive';
  const just = t.split(/[\\/]/).pop();
  return just
    .replace(/\.(zip|tgz|tar\.gz|gz|tar|7z|tbz2|tar\.bz2|bz2)$/i, '')
    .replace(/[^\w.\-]+/g, '_')
    .slice(0, 120) || 'archive';
}
function pickRunToken(b){
  const t = s(b.combinedLogToken || '').trim();
  if (t) return t.replace(/[^\w.\-]+/g, '_').slice(0, 80);
  const f = s(b.sourceFileId || '').trim();
  if (f) return ('fid_' + f.replace(/[^\w.\-]+/g, '_').slice(0, 60));
  return `${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}
function writeTmpText(b, tag, text){
  cleanupOld(TMP_ROOT, TTL_HOURS);
  ensureDir(TMP_ROOT);
  const runToken = pickRunToken(b);
  const srcBase = safeBaseName(
    b.sourceFileName || b.archiveName || b.fileName ||
    (Array.isArray(b.files) && b.files[0] && b.files[0].name) || ''
  );
  const dir = path.join(TMP_ROOT, `run_${runToken}`);
  ensureDir(dir);
  const fn = `${srcBase}__${tag}.txt`.replace(/[^\w.\-]+/g, '_').slice(0, 180);
  const fp = path.join(dir, fn);
  fs.writeFileSync(fp, s(text), 'utf8');
  return fp;
}

function dedupLinesMax(text, maxPerLine){
  const counts = new Map();
  const out = [];
  let removed = 0;
  for (const raw of s(text).replace(/\r\n/g, '\n').split('\n')) {
    const line = raw; // preserve original
    const key = line.trim().replace(/\s+/g, ' ').toLowerCase();
    if (!key) { out.push(line); continue; }
    const c = counts.get(key) || 0;
    if (c >= maxPerLine) { removed++; continue; }
    counts.set(key, c + 1);
    out.push(line);
  }
  return { text: out.join('\n'), removed };
}

function readLinesStream(fp, onLine){
  const fd = fs.openSync(fp, 'r');
  const BUF = Buffer.alloc(1024 * 1024);
  let carry = '';
  try {
    while (true) {
      const n = fs.readSync(fd, BUF, 0, BUF.length, null);
      if (!n) break;
      const chunk = carry + BUF.slice(0, n).toString('utf8');
      const parts = chunk.split(/\r?\n/);
      carry = parts.pop() || '';
      for (const ln of parts) onLine(ln);
    }
    if (carry) onLine(carry);
  } finally {
    try { fs.closeSync(fd); } catch {}
  }
}

// Capture first occurrence of each CLI block.
function extractCliBlocksFromFile(fp){
  const targets = [
    { key: 'enclosures', marker: '# show enclosures', maxLines: 6000 },
    { key: 'redundancy', marker: '# show redundancy-mode', maxLines: 1500 },
    { key: 'versions',   marker: '# show versions detail', maxLines: 2500 },
  ];

  const state = {};
  for (const t of targets) {
    state[t.key] = { ...t, found:false, done:false, lines:[] };
  }

  readLinesStream(fp, (rawLine) => {
    const line = s(rawLine).replace(/\r/g, '');
    const trimmed = line.trim();

    // Start block only if not found yet
    for (const k of Object.keys(state)) {
      const st = state[k];
      if (!st.found && trimmed === st.marker) {
        st.found = true;
        st.lines.push(line);
      }
    }

    // Append to active blocks
    for (const k of Object.keys(state)) {
      const st = state[k];
      if (!st.found || st.done) continue;

      // marker line already pushed at start
      if (!(trimmed === st.marker && st.lines.length === 1)) {
        st.lines.push(line);
      }

      // stop conditions
      if (st.lines.length >= st.maxLines) {
        st.done = true;
        continue;
      }
      if (st.lines.length > 1 && /^#\s+/.test(trimmed) && trimmed !== st.marker) {
        // a new command starts => rollback this line from current block
        st.lines.pop();
        st.done = true;
        continue;
      }
      if (/^Success:\s*Command completed\b/i.test(trimmed)) {
        st.done = true;
        continue;
      }
    }
  });

  const b1 = state.enclosures.lines.join('\n').trim();
  const b2 = state.redundancy.lines.join('\n').trim();
  const b3 = state.versions.lines.join('\n').trim();
  return { b1, b2, b3 };
}

// Fallback: keep keyword lines + small context windows.
// Helps when CLI markers are missing or logs differ.
function fallbackKeywordWindows(fp){
  const keywords = [
    '# show enclosures',
    '# show redundancy-mode',
    '# show versions detail',
    'Midplane',
    'MidplaneType',
    'Array',
    'EMP_A',
    'EMP_B',
    'Active-Active',
    'RedundancyMode',
    'RedundancyStatus',
    'TopLevelAssemblyPartNumber',
    'enclosure',
    'controller',
  ].map((x) => String(x).toLowerCase());

  const PREV = 3;
  const NEXT = 4;
  const ring = [];
  const out = [];
  const counts = new Map();
  let after = 0;
  let hits = 0;

  function push(line){
    const key = s(line).trim().replace(/\s+/g, ' ').toLowerCase();
    if (!key) return;
    const c = counts.get(key) || 0;
    if (c >= 3) return; // strict duplicate rule
    counts.set(key, c + 1);
    out.push(line);
  }

  readLinesStream(fp, (rawLine) => {
    const line = s(rawLine).replace(/\r/g, '');
    const low = line.toLowerCase();
    const isHit = keywords.some((k) => low.includes(k));

    if (isHit) {
      hits++;
      for (const prev of ring) push(prev);
      push(line);
      after = NEXT;
    } else if (after > 0) {
      push(line);
      after--;
    }

    ring.push(line);
    if (ring.length > PREV) ring.shift();
  });

  const txt = out.join('\n').trim();
  return { txt, hits };
}

if (!fileExists(SRC)) {
  const msg = `[n8n] Storage Structure Extract: combinedLogPath missing or unreadable: ${SRC || 'N/A'}`;
  const snipPath = writeTmpText(base, 'llm2_structure_evidence', msg);
  return [{
    json: {
      ...base,
      llm2_snip_path: snipPath,
      llm2_snip_chars: msg.length,
      llm2_extract_mode: 'error',
      llm2_extract_blocks: { enclosures:false, redundancy:false, versions:false },
      llm2_extract_dedup_removed: 0,
      digest_structure_text: '', // avoid payload bloat in Executions
      llm2_structure_preview: msg.slice(0, 1000),
    }
  }];
}

let digest = '';
let mode = 'wf4225_cli_blocks';
let dedupRemoved = 0;
let fallbackHits = 0;
const blocks = extractCliBlocksFromFile(SRC);

if (blocks.b1 || blocks.b2 || blocks.b3) {
  digest = [
    blocks.b1 ? '=== # show enclosures ===\n' + blocks.b1 : '',
    blocks.b2 ? '=== # show redundancy-mode ===\n' + blocks.b2 : '',
    blocks.b3 ? '=== # show versions detail ===\n' + blocks.b3 : '',
  ].filter(Boolean).join('\n\n');
} else {
  mode = 'keyword_windows_fallback';
  const fb = fallbackKeywordWindows(SRC);
  fallbackHits = fb.hits;
  digest = fb.txt || '[n8n] No structure blocks found.';
}

// Global de-dup (max 3 repeats)
{
  const r = dedupLinesMax(digest, 3);
  digest = r.text;
  dedupRemoved = r.removed;
}

// Optional clipping only if env explicitly configured
if (MAX_CHARS > 0 && digest.length > MAX_CHARS) {
  digest = digest.slice(0, MAX_CHARS) + '\n[n8n] TRUNCATED';
}

const snipPath = writeTmpText(base, 'llm2_structure_evidence', digest);

return [{
  json: {
    ...base,
    llm2_snip_path: snipPath,
    llm2_snip_chars: digest.length,
    llm2_extract_mode: mode,
    llm2_extract_blocks: {
      enclosures: !!blocks.b1,
      redundancy: !!blocks.b2,
      versions: !!blocks.b3,
      fallbackHits,
    },
    llm2_extract_dedup_removed: dedupRemoved,
    digest_structure_text: '', // keep executions small; Compose reads llm2_snip_path
    llm2_structure_preview: s(digest).slice(0, 1200), // tiny debug preview only
  }
}];

// Storage Disks Extract — FULL REPLACE v6.1-wf4225-blocks-from-ulc
// LLM3: take combinedLogPath from ULC, extract "# show disks" CLI blocks like WF4225,
// dedup duplicate lines (>3), save evidence to local temp file (not to Executions).

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const base = $input.item.json || {};
const s = (x) => (x == null ? '' : String(x));

const TMP_ROOT = s($env.LOGPARSER_LLM_TMP_ROOT || '/home/node/.n8n/tmp/logparser_llm').trim() || '/home/node/.n8n/tmp/logparser_llm';
const TTL_HOURS = Number($env.LOGPARSER_LLM_TTL_HOURS || 72);
const MAX_REPEAT = Number($env.LOGPARSER_MAX_REPEAT_LINES || 3);
const MAX_LINES_OUT = Number($env.LLM3_MAX_LINES_OUT || 1400); // WF4225 behavior (configurable)

function ensureDir(p){ try { fs.mkdirSync(p, { recursive: true }); } catch {} }

function cleanupOld(root, ttlHours){
  try {
    if (!fs.existsSync(root)) return;
    const now = Date.now();
    for (const name of fs.readdirSync(root)) {
      const p = path.join(root, name);
      let st;
      try { st = fs.statSync(p); } catch { continue; }
      if (!st.isDirectory()) continue;
      const ageH = (now - st.mtimeMs) / 3600000;
      if (ageH > ttlHours) {
        try { fs.rmSync(p, { recursive:true, force:true }); } catch {}
      }
    }
  } catch {}
}

function safeBaseName(name){
  const t = s(name).trim();
  if (!t) return 'archive';
  const just = t.split(/[\\/]/).pop();
  return just.replace(/\.(zip|tgz|tar\.gz|gz|tar|7z|tbz2|tar\.bz2|bz2)$/i,'').replace(/[^\w.\-]+/g,'_').slice(0,120) || 'archive';
}

function pickRunToken(base){
  const t = s(base.combinedLogToken || '').trim();
  if (t) return t.replace(/[^\w.\-]+/g,'_').slice(0,80);
  const f = s(base.sourceFileId || '').trim();
  if (f) return ('fid_' + f.replace(/[^\w.\-]+/g,'_').slice(0,60));
  return `${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}

function writeFile(base, taskTag, content){
  cleanupOld(TMP_ROOT, TTL_HOURS);
  ensureDir(TMP_ROOT);
  const runToken = pickRunToken(base);
  const srcBase = safeBaseName(base.sourceFileName || base.archiveName || base.fileName || '');
  const dir = path.join(TMP_ROOT, `run_${runToken}`);
  ensureDir(dir);
  const fp = path.join(dir, `${srcBase}__${taskTag}.txt`.replace(/[^\w.\-]+/g,'_').slice(0,180));
  fs.writeFileSync(fp, s(content), 'utf8');
