  let removed = 0;
  for (const raw of s(text).replace(/\r\n/g,'\n').split('\n')) {
    const line = raw;
    const key = line.trim().replace(/\s+/g,' ').toLowerCase();
    if (!key) { out.push(line); continue; }
    const c = counts.get(key) || 0;
    if (c >= maxPerLine) { removed++; continue; }
    counts.set(key, c + 1);
    out.push(line);
  }
  return { text: out.join('\n'), removed };
}

function extractShowDisksBlocks(fp){
  const out = [];
  let inBlock = false;
  let lineCount = 0;

  readLinesStream(fp, (line) => {
    const plain = stripSourcePrefix(line);
    const low = plain.toLowerCase().trim();

    // Start marker (WF4225 pattern)
    if (/#\s*show\s+disks\b/i.test(plain)) {
      inBlock = true;
      lineCount = 0;
      out.push(plain);
      return;
    }

    if (inBlock) {
      // Stop at next CLI command marker (WF4225 style)
      if (/^\s*#\s+/.test(low)) {
        inBlock = false;
        return;
      }
      out.push(plain);
      lineCount++;
      if (MAX_LINES_OUT > 0 && lineCount >= MAX_LINES_OUT) {
        inBlock = false;
      }
    }
  });

  return out.join('\n');
}

function fallbackRegexDigest(fp){
  const keep = [];
  const rx = /(^\s*(encl|enclosure|disk|drive|slot|bay|pd)\b|wwn|serial|part|vendor|model|size|rpm|health|state|firmware|sas|sata|nvme|location:|^[-=]{4,})/i;
  readLinesStream(fp, (line) => {
    const plain = stripSourcePrefix(line);
    if (rx.test(plain)) keep.push(plain);
  });
  return keep.join('\n');
}

const src = resolveCombinedPath(base);

if (!src.ok) {
  const msg = `[n8n] Storage Disks Extract failed: ${src.error}`;
  const fp = writeFile(base, 'llm3_disks_evidence', msg);
