function readHeadText(fp, maxChars){
  const txt = fs.readFileSync(fp, 'utf8');
  return (maxChars > 0 && txt.length > maxChars) ? txt.slice(0, maxChars) : txt;
}

// More robust than old version:
// - removes any leading garbage before [source ...]
// - then trims leading junk before first "# show ..." when present
function stripSourcePrefix(line){
  let x = s(line).replace(/\r/g, '');

  // remove everything through "[source ...]" if present anywhere in line
  x = x.replace(/^.*?\[source\s+[^\]]+\]\s*/i, '');

  // if command exists later in line, cut to the command start
  const cliIdx = x.toLowerCase().indexOf('# show ');
  if (cliIdx > 0) x = x.slice(cliIdx);

  return x;
}

function dedupLinesMax(text, maxRepeat){
  const counts = new Map();
  const out = [];
  let removed = 0;

  for (const raw of s(text).replace(/\r\n/g,'\n').split('\n')) {
    const ln = raw.trimEnd();

    if (!ln) {
      if (out.length && out[out.length - 1] !== '') out.push('');
      continue;
    }

    const key = ln;
    const c = (counts.get(key) || 0) + 1;
    counts.set(key, c);

    if (c <= maxRepeat) out.push(ln);
    else removed++;
  }

  while (out.length && out[out.length - 1] === '') out.pop();
  return { text: out.join('\n'), removed };
}

function clip(t, n){
  const x = s(t);
  if (!n || x.length <= n) return x;
  return x.slice(0, n) + `\n[n8n] TRUNCATED to ${n} chars`;
}

function escRe(x){
  return s(x).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function hasCmd(line, cmd){
  // Detect "# show <cmd>" anywhere in the line, not only at start
  const re = new RegExp(`(?:^|\\s)${escRe(cmd)}(?:\\s|$)`, 'i');
  return re.test(s(line));
}

function isAnyCliShow(line){
  return /(?:^|\s)#\s+show\s+/i.test(s(line));
}

function extractCliBlock(text, commandName, maxLines){
  const cmd = s(commandName).trim();
  const lines = s(text).replace(/\r\n/g,'\n').split('\n');

  const out = [];
  let started = false;
  let seenData = false;

  for (const raw of lines) {
    const plain = stripSourcePrefix(raw);
    const trimmed = plain.trim();

    if (!started) {
      if (hasCmd(trimmed, cmd)) {
        started = true;
        out.push(trimmed);
      }
      continue;
    }

    // stop at next CLI "show" command if it's not our command
    if (isAnyCliShow(trimmed) && !hasCmd(trimmed, cmd)) break;
    if (/(?:^|\s)#\s+exit\b/i.test(trimmed)) break;

    out.push(trimmed);

    if (trimmed && !/^success:/i.test(trimmed)) seenData = true;
    if (maxLines > 0 && out.length >= maxLines) break;

    // optional graceful stop after command completion
    if (seenData && /^success:/i.test(trimmed)) break;
  }

  return out.join('\n').trim();
}

function extractSfpEvidence(text, maxLines){
  const out = [];
  const counts = new Map();

  function push(line){
    const t = s(line).trimEnd();
    if (!t) return;
    const c = (counts.get(t) || 0) + 1;
    counts.set(t, c);
    if (c <= 4 && out.length < maxLines) out.push(t);
  }

  // Priority: # show ports block
  const portsBlock = extractCliBlock(text, '# show ports', 6000);
  if (portsBlock) {
    const lines = portsBlock.split('\n');
    let inPortsTable = false;

    for (const raw of lines) {
      const line = raw.trimEnd();

      if (/^Ports\s+Media\s+/i.test(line)) {
        inPortsTable = true;
        push(line);
        continue;
      }

      if (inPortsTable) {
        if (/^[-\s]+$/.test(line)) { push(line); continue; }
        if (/^[AB]\d+\s+/i.test(line)) { push(line); continue; }

        // stop table on obvious next section
        if (/^(Success:|#\s+show\s+)/i.test(line)) inPortsTable = false;
      }

      // detailed SFP attributes
      if (/\bSFP\s+Status\b/i.test(line)) push(line);
      if (/\bPart Number\b/i.test(line)) push(line);
      if (/\bSerial Number\b/i.test(line)) push(line);
      if (/\bSupported Speeds\b/i.test(line)) push(line);
      if (/\bConnector Type\b/i.test(line)) push(line);
      if (/^\s*Port\s*:\s*[AB]\d+\b/i.test(line)) push(line);
    }
  }

  // Fallback if ports block missing
  if (!out.length) {
    const rx = /(\bSFP\b|\btransceiver\b|\bSupported Speeds\b|\bPart Number\b|\bSerial Number\b|^Ports\s+Media\s+)/i;
    for (const raw of s(text).replace(/\r\n/g,'\n').split('\n')) {
      const line = stripSourcePrefix(raw).trimEnd();
      if (!line) continue;
      if (!rx.test(line)) continue;
      push(line);
      if (out.length >= maxLines) break;
    }
  }

  return out.join('\n').trim();
}

// Strict FAN fallback rule: word boundary + useful fan context
const RX_FAN_WORD    = /\b(?:fan|fans|fan-module|fan\s+module)\b/i;
const RX_FAN_CONTEXT = /\b(?:health|status|rpm|encl|enclosure|psu|left|right|module|fan-id|location)\b/i;

function looksFanLine(line){
  const x = s(line);
  return RX_FAN_WORD.test(x) && RX_FAN_CONTEXT.test(x);
}

function looksPsuLine(line){
  return /(#\s+show\s+power-supplies\b|\bpower[\s-]*supply\b|\bpsu\b|\bpower-cooling\b|\bdc12v\b|\bfruv\b|\bcutv\b)/i.test(line);
}

function looksSfpLine(line){
  return /(#\s+show\s+ports\b|^Ports\s+Media\s+|^[AB]\d+\s+.*\bSFP\b|\bSFP\b|\btransceiver\b|\bSupported Speeds\b|\bConnector Type\b|\bPart Number\b|\bSerial Number\b)/i.test(line);
}

function extractFallbackPeriphery(text, maxLines){
  const out = [];
  const counts = new Map();

  function push(line){
    const t = s(line).trimEnd();
    if (!t) return;
    const c = (counts.get(t) || 0) + 1;
    counts.set(t, c);
    if (c <= 3 && out.length < maxLines) out.push(t);
  }

  for (const raw of s(text).replace(/\r\n/g,'\n').split('\n')) {
    const line = stripSourcePrefix(raw).trimEnd();
    if (!line) continue;

    // Keep explicit command lines
    if (/#\s+show\s+(power-supplies|fans|ports)\b/i.test(line)) {
      push(line);
      continue;
    }

    if (looksPsuLine(line)) { push(line); continue; }
    if (looksFanLine(line)) { push(line); continue; }
    if (looksSfpLine(line)) { push(line); continue; }
  }

  return out.join('\n').trim();
}

const src = resolveCombinedPath(base);

if (!src.ok) {
