function unzipList(xlsxPath){
  // Try standard unzip -Z1 first (full unzip), fallback to BusyBox unzip -l parser
  let r = shTxt('unzip', ['-Z1', xlsxPath]);
  if (r.ok && r.stdout.trim()) {
    return r.stdout.split(/\r?\n/).map(x => x.trim()).filter(Boolean);
  }

  r = shTxt('unzip', ['-l', xlsxPath]);
  if (!r.ok) return [];

  const out = [];
  const lines = r.stdout.split(/\r?\n/);
