  x = x.replace(/&#x([0-9a-f]+);/ig, (_,h)=>String.fromCharCode(parseInt(h,16)));
  x = x.replace(/&#(\d+);/g, (_,d)=>String.fromCharCode(parseInt(d,10)));
  return x;
}

function parseSharedStrings(xml){
  const out = [];
  if (!xml) return out;
  const siRe = /<si\b[^>]*>([\s\S]*?)<\/si>/g;
  let m;
  while ((m = siRe.exec(xml))) {
    const block = m[1];
    const tRe = /<t\b[^>]*>([\s\S]*?)<\/t>/g;
    let t, parts = [];
    while ((t = tRe.exec(block))) parts.push(decodeXmlEntities(t[1]));
    out.push(parts.join(''));
  }
  return out;
}

function parseSheetRows(sheetXml, sharedStrings){
  const rows = new Map();
  if (!sheetXml) return rows;

  const rowRe = /<row\b[^>]*r="(\d+)"[^>]*>([\s\S]*?)<\/row>/g;
  const cellRe = /<c\b([^>]*)>([\s\S]*?)<\/c>/g;

  let rm;
  while ((rm = rowRe.exec(sheetXml))) {
    const rowNum = parseInt(rm[1], 10);
    const rowBlock = rm[2];
    const rowObj = {};

    let cm;
    while ((cm = cellRe.exec(rowBlock))) {
      const attrs = cm[1] || '';
      const inner = cm[2] || '';

      const refM = attrs.match(/\br="([A-Z]+)(\d+)"/);
      if (!refM) continue;
      const col = refM[1];

      const tM = attrs.match(/\bt="([^"]+)"/);
      const typ = tM ? tM[1] : '';

      let val = '';
      if (typ === 's') {
        const vM = inner.match(/<v>([\s\S]*?)<\/v>/);
        if (vM) {
          const idx = parseInt(vM[1],10);
          val = (idx >= 0 && idx < sharedStrings.length) ? sharedStrings[idx] : '';
        }
      } else if (typ === 'inlineStr') {
        const tM2 = inner.match(/<t\b[^>]*>([\s\S]*?)<\/t>/);
        if (tM2) val = decodeXmlEntities(tM2[1]);
      } else {
        const vM = inner.match(/<v>([\s\S]*?)<\/v>/);
        if (vM) val = decodeXmlEntities(vM[1]);
      }

      val = s(val).trim();
      if (val) rowObj[col] = val;
    }

    rows.set(rowNum, rowObj);
  }

  return rows;
}

function loadKeywordsFromXlsxNoLib(xlsxPath){
  const debug = {
    mode: 'no-xlsx-lib',
    xlsxPath,
    loaded: 0,
    usedFallback: false,
    error: '',
    listMode: '',
    sheetPath: '',
    sharedPath: '',
  };

  if (!fileExists(xlsxPath)) {
    debug.error = 'XLSX not found';
    return { keywords: [], debug };
  }

  const unzipOk = shTxt('sh', ['-lc', 'command -v unzip >/dev/null 2>&1 && echo ok || echo no']);
  if (!unzipOk.ok || !unzipOk.stdout.includes('ok')) {
    debug.error = 'unzip not found';
    return { keywords: [], debug };
  }

  const list = unzipList(xlsxPath);
  debug.listMode = list.length ? 'ok' : 'empty';
  if (!list.length) {
    debug.error = 'cannot list xlsx entries';
    return { keywords: [], debug };
  }

  const sheetPath =
    list.find(x => /^xl\/worksheets\/sheet\d+\.xml$/i.test(x)) ||
    list.find(x => x.toLowerCase().startsWith('xl/worksheets/') && x.toLowerCase().endsWith('.xml')) ||
    '';
  const sharedPath = list.find(x => x.toLowerCase() === 'xl/sharedstrings.xml') || '';

  debug.sheetPath = sheetPath;
  debug.sharedPath = sharedPath;

  const sharedXml = sharedPath ? unzipReadText(xlsxPath, sharedPath) : '';
  const sharedStrings = sharedXml ? parseSharedStrings(sharedXml) : [];
  const sheetXml = sheetPath ? unzipReadText(xlsxPath, sheetPath) : '';
  const rows = parseSheetRows(sheetXml, sharedStrings);

  const header = rows.get(1) || {};
  const headerEntries = Object.entries(header).map(([c,v]) => [c, s(v).trim().toLowerCase()]);
  function findCol(candidates){
    for (const [col,val] of headerEntries) {
      for (const c of candidates) {
        if (val === c || val.includes(c)) return col;
      }
    }
    return '';
  }

  const colKeyword = findCol(['keyword','phrase','text']) || (Object.keys(header)[0] || 'A');

  const seen = new Set();
  const keywords = [];
  for (let r = 2; r <= 200000; r++) {
    const row = rows.get(r);
    if (!row) continue;
    let k = s(row[colKeyword]).trim();
    if (!k) continue;
    if (k.length > 240) continue;
    const low = k.toLowerCase();
    if (low === 'keyword' || low === 'phrase' || low === 'text') continue;
    if (seen.has(low)) continue;
    seen.add(low);
    keywords.push(k);
    if (keywords.length >= 5000) break;
  }

  debug.loaded = keywords.length;
  return { keywords, debug };
}

// ---------- load keywords ----------
const XLSX_PATH =
  s($env.STORAGE_ERROR_KEYWORDS_XLSX).trim() ||
  '/srv/yadisk/LLM QLoRA/LOGparser/storage_error_keywords.xlsx';

let kwRes = { keywords: [], debug: {} };
try {
  kwRes = loadKeywordsFromXlsxNoLib(XLSX_PATH);
} catch (e) {
  kwRes = {
    keywords: [],
    debug: {
      mode: 'no-xlsx-lib',
      xlsxPath: XLSX_PATH,
      loaded: 0,
      usedFallback: false,
      error: s(e && e.message),
    }
  };
}

let keywords = Array.isArray(kwRes.keywords) ? kwRes.keywords : [];
const keywordsDebug = kwRes.debug || {};

if (!keywords.length) {
  keywordsDebug.usedFallback = true;
  keywords = [
    'quarantine', 'quarantined', 'fault', 'degraded', 'offline', 'missing',
    'disk group', 'drive failed', 'virtual disk fault', 'controller fault',
    'uncorrectable', 'error', 'critical', 'panic', 'assert', 'rebuild', 'failover'
  ];
}

// ---------- extractor params ----------
const BEFORE = Number($env.LLM5_CTX_BEFORE || 2);
const AFTER = Number($env.LLM5_CTX_AFTER || 4);
const MAX_HITS = Number($env.LLM5_MAX_HITS || 6000);
const DUP_MAX = Number($env.LLM5_DUP_MAX || 3);
const REGEX_TERMS = Number($env.LLM5_REGEX_TERMS || 300);

// Regex from keywords (limit to keep regex sane)
function escapeRe(x){ return s(x).replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }
const regexTerms = keywords.slice(0, Math.max(1, REGEX_TERMS));
const bigRe = new RegExp(regexTerms.map(escapeRe).join('|'), 'i');

// ---------- output file ----------
cleanupOld(TMP_ROOT, TTL_HOURS);
ensureDir(TMP_ROOT);

const runToken = pickRunToken(base);
const srcBase = safeBaseName(base.sourceFileName || base.archiveName || '');
const dir = path.join(TMP_ROOT, `run_${runToken}`);
ensureDir(dir);

const outPath = path.join(dir, `${srcBase}__llm5_errors_keyword_snip.txt`.replace(/[^\w.\-]+/g,'_').slice(0, 200));
const fd = fs.openSync(outPath, 'w');

const counts = new Map();
let dupesSkipped = 0;
let linesWritten = 0;
let hits = 0;
let lineNo = 0;

const srcLabel = s(base.archiveName || base.sourceFileName || path.basename(combinedPath)).trim() || path.basename(combinedPath);

function writeLineRaw(line){
  fs.writeSync(fd, line.endsWith('\n') ? line : (line + '\n'));
  linesWritten++;
}

function writeSourceLine(n, payload){
  const key = normKey(payload);
  if (key) {
    const c = counts.get(key) || 0;
    if (c >= DUP_MAX) { dupesSkipped++; return; }
    counts.set(key, c + 1);
  }
  writeLineRaw(`[source ${srcLabel}:${n}] ${payload}`);
}

function readLinesStream(fp, onLine){
  const fdIn = fs.openSync(fp, 'r');
  const BUF = Buffer.alloc(1024 * 1024);
  let carry = '';
  try {
    while (true){
      const n = fs.readSync(fdIn, BUF, 0, BUF.length, null);
      if (!n) break;
      const chunk = carry + BUF.slice(0, n).toString('utf8');
      const parts = chunk.split(/\r?\n/);
      carry = parts.pop() || '';
      for (const ln of parts) onLine(ln);
    }
    if (carry) onLine(carry);
  } finally {
    try { fs.closeSync(fdIn); } catch {}
  }
}

const ring = []; // { n, t }
let afterCountdown = 0;

try {
  writeLineRaw('LLM5 KEYWORD SNIPPET (errors)');
  writeLineRaw(`source=${combinedPath}`);
  writeLineRaw(`archive=${s(base.archiveName)}`);
  writeLineRaw(`file=${s(base.sourceFileName)}`);
  writeLineRaw(`xlsx=${XLSX_PATH}`);
  writeLineRaw(`keywords=${keywords.length}`);
  writeLineRaw('---');
  writeLineRaw('');

  readLinesStream(combinedPath, (raw) => {
    lineNo++;
    const line = s(raw).replace(/\r/g, '');
    if (!line) return;

    // continuation context after a hit
    if (afterCountdown > 0) {
      writeSourceLine(lineNo, `[ctx+] ${line}`);
      afterCountdown--;
      ring.push({ n: lineNo, t: line });
      if (ring.length > BEFORE) ring.shift();
      return;
    }

    ring.push({ n: lineNo, t: line });
    if (ring.length > BEFORE) ring.shift();

    if (!bigRe.test(line)) return;

    hits++;
    if (hits > MAX_HITS) return;

    writeLineRaw('');
    writeLineRaw('===== HIT =====');
    for (const r of ring.slice(0, -1)) {
      writeSourceLine(r.n, `[ctx-] ${r.t}`);
    }
    writeSourceLine(lineNo, `[hit] ${line}`);
    afterCountdown = AFTER;
  });

  if (hits > MAX_HITS) {
    writeLineRaw(`[n8n] HIT LIMIT REACHED: ${MAX_HITS}`);
  }

} finally {
  try { fs.closeSync(fd); } catch {}
}

const outBytes = (() => { try { return fs.statSync(outPath).size; } catch { return 0; } })();

const eventCatalogContext =
  `ERROR KEYWORDS CATALOG (LOCAL)\n` +
  `Source: ${XLSX_PATH}\n` +
  `Keywords: ${keywords.length}\n` +
  `RegexTermsUsed: ${regexTerms.length}\n` +
  `Extractor: keyword+context\n`;

return [{
  json: {
    ...base,

    task: 'storage_errors',
    taskOrder: 5,
    model: MODEL,

    // downstream catalog fields
    event_catalog_targets: keywords,
    event_catalog_context_text: eventCatalogContext,
