    _errors_keywords_path: XLSX_PATH,
    _errors_keywords_error: s(keywordsDebug.error || ''),
    _errors_terms_count: keywords.length,
    _errors_matches_total: hits,
    _errors_extract_ok: true,
    _errors_extract_error: '',
    _errors_extract_stats: {
      before: BEFORE,
      after: AFTER,
      maxHits: MAX_HITS,
      dupMax: DUP_MAX,
      regexTermsUsed: regexTerms.length,
      linesWritten,
      dupesSkipped,
      hits,
    },

    _keywords_debug: keywordsDebug,
  }
}];

// Assemble Storage Report — FULL REPLACE v6-table-format-spaced-separators
// Output formatting rules:
// 1) Drop columns where ALL rows are empty or N/A.
// 2) Render tables as aligned text (spaces), not semicolon-separated.
// 3) Between tables add a blank line + separator + blank line.

function s(x){ return x == null ? "" : String(x); }

const SEP_LINE = "======================================================";
const COL_GAP = "  "; // at least 2 spaces

function extractAssistantText(j) {
  if (!j || typeof j !== "object") return "";
  if (typeof j.message?.content === "string") return j.message.content;
  if (typeof j.ollama?.message?.content === "string") return j.ollama.message.content;
  if (typeof j.response === "string") return j.response;
  if (typeof j.text === "string") return j.text;
  return "";
}

function stripThink(raw) {
  return s(raw).replace(/<think>[\s\S]*?<\/think>/gi, "").trim();
}

function stripCodeFences(raw) {
  const t = s(raw).trim();
  const m = t.match(/^```[a-z0-9_-]*\s*([\s\S]*?)\s*```$/i);
  return m ? m[1].trim() : t;
}

function normTask(t){
  const x = s(t).trim().toLowerCase();
  if (x.includes("structure")) return "structure";
  if (x.includes("disk")) return "disks";
  if (x.includes("periph")) return "periphery";
  if (x.includes("error")) return "errors";
  return "unknown";
}

function collectAllItems(){
  const out = [];
  try { for (const it of $input.all()) out.push(it.json || {}); }
  catch { out.push($input.item.json || {}); }
  return out;
}

function nowMSK() {
  try {
    const d = new Date();
    const dtf = new Intl.DateTimeFormat("en-GB", {
      timeZone: "Europe/Moscow",
      year: "numeric", month: "2-digit", day: "2-digit",
      hour: "2-digit", minute: "2-digit", second: "2-digit",
      hour12: false,
    });
    const parts = dtf.format(d).replace(",", "");
    const m = parts.match(/^(\d{2})\/(\d{2})\/(\d{4})\s+(\d{2}):(\d{2}):(\d{2})$/);
    if (!m) return parts + " (MSK)";
    return `${m[1]}-${m[2]}-${m[3]} ${m[4]}:${m[5]}:${m[6]} (MSK)`;
  } catch {
    const d = new Date(Date.now() + 3*3600*1000);
    return d.toISOString().replace("T"," ").replace("Z","") + " (MSK~)";
  }
}

function extractErrorsOnly(raw) {
  let t = stripCodeFences(stripThink(raw)).trim();
  if (!t) return "";

  const idxTable = t.toUpperCase().indexOf("TABLE: ERRORS");
  if (idxTable >= 0) return t.slice(idxTable).trim();

  const reAll = /(^|\n)\s*4\)\s*Errors:\s*/gi;
  let last = -1;
  let m;
  while ((m = reAll.exec(t)) !== null) last = m.index;
  if (last >= 0) {
    const cut = t.slice(last);
    return cut.replace(/^\s*4\)\s*Errors:\s*/i, "").trim();
  }

  return t.trim();
}

function isNA(val) {
  const v = s(val).trim();
  if (!v) return true;
  const low = v.toLowerCase();
  return low === "n/a" || low === "na" || low === "-" || low === "none";
}

function parseRow(line, delim, nCols) {
  const parts = s(line).split(delim).map(x => x.trim());
  if (nCols <= 1) return parts;
  if (parts.length === nCols) return parts;

  if (parts.length < nCols) {
    while (parts.length < nCols) parts.push("");
    return parts;
  }

  // too many splits: merge tail into last cell (safe for rows where message/value contains ';')
  const head = parts.slice(0, nCols - 1);
  const tail = parts.slice(nCols - 1).join(delim).trim();
  return head.concat([tail]);
}

function detectDelimiter(headerLine) {
  const l = s(headerLine);
  if (l.includes(";")) return ";";
  if (l.includes("\t")) return "\t";
  return "";
}

function formatTable(name, headerLine, rowLines) {
  const delim = detectDelimiter(headerLine);

  if (!delim) {
    // Not a delimited table; return as-is
    const body = [headerLine].concat(rowLines || []).join("\n").trim();
    return [`TABLE: ${name}`, body || "N/A"].join("\n").trim();
  }

  const headers = parseRow(headerLine, delim, 999);
  const nCols = headers.length;

  // rows
  let rows = [];
  for (const rl of rowLines) {
    const r = s(rl).trim();
    if (!r) continue;
    if (r.toUpperCase() === "N/A") continue;
    rows.push(parseRow(r, delim, nCols));
  }

  if (!rows.length) {
    return [`TABLE: ${name}`, "N/A"].join("\n");
  }

  // drop columns where ALL rows are N/A/empty
  const keepIdx = [];
  for (let c = 0; c < nCols; c++) {
    let allEmpty = true;
    for (const r of rows) {
      if (!isNA(r[c])) { allEmpty = false; break; }
    }
    if (!allEmpty) keepIdx.push(c);
  }

  if (!keepIdx.length) {
    return [`TABLE: ${name}`, "N/A"].join("\n");
  }

  const keptHeaders = keepIdx.map(i => headers[i] || "");
  const keptRows = rows.map(r => keepIdx.map(i => r[i] || ""));

  // widths: align ALL columns so data stays strictly under headers (important for LLM3 tables)
  const widths = keptHeaders.map(h => Math.max(3, s(h).length));
  for (const r of keptRows) {
    for (let i = 0; i < r.length; i++) {
      widths[i] = Math.max(widths[i], s(r[i]).length);
    }
  }

  function fmtLine(cells) {
    const out = [];
    for (let i = 0; i < cells.length; i++) {
      const v = s(cells[i]).trim();
      out.push(v.padEnd(widths[i], " "));
    }
    return out.join(COL_GAP).replace(/\s+$/,'');
  }

  const lines = [];
  lines.push(`TABLE: ${name}`);
  lines.push(fmtLine(keptHeaders));
  for (const r of keptRows) lines.push(fmtLine(r));

  return lines.join("\n").trim();
}

function pushTableSeparator(outArr) {
  // exactly:
  // <blank>
  // ======================================================
  // <blank>
  outArr.push("");
  outArr.push(SEP_LINE);
  outArr.push("");
}

function formatTablesInText(text) {
  const t = s(text).replace(/\r\n/g, "\n").trim();
  if (!t) return "";

  const lines = t.split("\n");
  const out = [];
  let i = 0;
  let tablesEmitted = 0;

  while (i < lines.length) {
    const line = lines[i];

    const m = line.match(/^\s*TABLE:\s*(.+?)\s*$/i);
    if (!m) {
      out.push(line);
      i++;
      continue;
    }

    const name = s(m[1]).trim();

    // find header line
    i++;
    while (i < lines.length && !lines[i].trim()) i++;

    if (i >= lines.length) {
      if (tablesEmitted > 0) pushTableSeparator(out);
      out.push(`TABLE: ${name}`);
      out.push("N/A");
      tablesEmitted++;
      break;
    }

    if (lines[i].trim().toUpperCase() === "N/A") {
      if (tablesEmitted > 0) pushTableSeparator(out);
      out.push(`TABLE: ${name}`);
      out.push("N/A");
      tablesEmitted++;
      i++;
      continue;
    }

    const headerLine = lines[i];
    i++;

    const rowLines = [];
    while (i < lines.length) {
      const cur = lines[i];
      if (/^\s*TABLE:\s*/i.test(cur)) break;
      rowLines.push(cur);
      i++;
    }

    if (tablesEmitted > 0) pushTableSeparator(out);
    out.push(formatTable(name, headerLine, rowLines));
    tablesEmitted++;
  }

  // Preserve intentional blank lines around separators; only trim outer edges
  return out.join("\n").trim();
}

// ---------------- MAIN ----------------
const items = collectAllItems();
const any = items.find(it => it.hw_vendor || it.vendor || it.klass || it.modelDetected) || items[0] || {};

const byTask = { structure: [], disks: [], periphery: [], errors: [] };
for (const it of items) {
  const t = normTask(it.task);
  if (byTask[t]) byTask[t].push(it);
}

function bestRaw(task){
  const arr = byTask[task] || [];
  if (!arr.length) return "";
  arr.sort((a,b) => extractAssistantText(b).length - extractAssistantText(a).length);
  return extractAssistantText(arr[0]);
}

const rawStruct0 = stripCodeFences(stripThink(bestRaw("structure")));
const rawDisks0  = stripCodeFences(stripThink(bestRaw("disks")));
const rawPer0    = stripCodeFences(stripThink(bestRaw("periphery")));
const rawErrRaw  = bestRaw("errors");
const rawErr0    = extractErrorsOnly(rawErrRaw);

// APPLY TABLE FORMATTER
const rawStruct = formatTablesInText(rawStruct0) || (rawStruct0.trim() ? rawStruct0.trim() : "N/A");
const rawDisks  = formatTablesInText(rawDisks0)  || rawDisks0.trim();
const rawPer    = formatTablesInText(rawPer0)    || rawPer0.trim();
