const reportLLM = s(any.ReportLLM || $env.LOGPARSER_REPORT_LLM || "qwen2.5:32b-instruct-q8_0").trim() || "qwen2.5:32b-instruct-q8_0";
const reportTs  = s(any.ReportTimestampMSK).trim() || nowMSK();

