const s = (x) => (x == null ? '' : String(x));

const TMP_ROOT = s($env.LOGPARSER_LLM_TMP_ROOT || '/home/node/.n8n/tmp/logparser_llm').trim() || '/home/node/.n8n/tmp/logparser_llm';
