  }
}

if (re) {
  if (sourceMode === 'file') {
    let dn = 0;
    readLinesStream(digestPath, (ln) => {
      dn++;
      if (confirmed.length >= 300) return;
      processLine(ln, dn);
    });
  } else if (sourceMode === 'text') {
    const lines = s(base.digest_errors_text).split(/\r?\n/);
    for (let i = 0; i < lines.length; i++) {
      if (confirmed.length >= 300) break;
      processLine(lines[i], i + 1);
    }
  }
}

const out = {
  ...base,

  confirmed_events: confirmed.slice(0, 300),
  dgA01_hits: dgHits.slice(0, 30),

  _matcher_mode: 'local-keyword-matcher-file',
  _matcher_confirmed: Math.min(confirmed.length, 300),
  _matcher_scanned_lines: scannedLines,
  _matcher_matched_lines: matchedLines,
  _matcher_digest_source: sourceMode,

  // Keep file-based flow, not text blobs
  digest_errors_text: '',
  llm_input: '',
  messages: [],
};

return [{ json: out }];

// Compose input ERRORS — FULL REPLACE v11-file-input-like-llm2
// Goal:
// - Build LLM5 prompt from confirmed_events + dgA01_hits (fallback: digest file excerpt)
// - Write evidence file + llm5_input file to disk
// - Keep execution payload tiny (like LLM2 compose)

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

function s(x){ return x == null ? '' : String(x); }

const base = $input.item.json || {};

const TMP_ROOT = '/home/node/.n8n/tmp/logparser_evidence';
const TTL_HOURS = Number($env.LOGPARSER_EVID_TTL_HOURS || 72);

function ensureDir(p){ try { fs.mkdirSync(p, { recursive: true }); } catch {} }

function cleanupOld(root, ttlHours){
  try {
    if (!fs.existsSync(root)) return;
    const ttlMs = ttlHours * 3600 * 1000;
    const now = Date.now();
    for (const d of fs.readdirSync(root)) {
      const fp = path.join(root, d);
      let st;
      try { st = fs.statSync(fp); } catch { continue; }
      const age = now - Number(st.mtimeMs || 0);
      if (age > ttlMs) {
        try { fs.rmSync(fp, { recursive: true, force: true }); } catch {}
      }
    }
  } catch {}
}

function safeBaseName(name){
  const t = s(name).trim();
  if (!t) return 'archive';
  const just = t.split(/[\\/]/).pop();
  return just
    .replace(/\.(zip|tgz|tar\.gz|gz|tar|7z|tbz2|tar\.bz2|bz2)$/i,'')
    .replace(/[^\w.\-]+/g,'_')
    .slice(0,120) || 'archive';
}

function pickRunToken(base){
  const t = s(base.combinedLogToken || '').trim();
  if (t) return t.replace(/[^\w.\-]+/g,'_').slice(0,80);
  const f = s(base.sourceFileId || '').trim();
  if (f) return ('fid_' + f.replace(/[^\w.\-]+/g,'_').slice(0,60));
  return `${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}

function writeTextFile(base, taskTag, text){
  cleanupOld(TMP_ROOT, TTL_HOURS);
  ensureDir(TMP_ROOT);

  const runToken = pickRunToken(base);
  const srcBase = safeBaseName(base.sourceFileName || base.archiveName || base.fileName || '');
  const dir = path.join(TMP_ROOT, `run_${runToken}`);
  ensureDir(dir);

  const fn = `${srcBase}__${taskTag}.txt`.replace(/[^\w.\-]+/g,'_').slice(0, 180);
  const fp = path.join(dir, fn);
  fs.writeFileSync(fp, s(text), 'utf8');
  return fp;
}

function dedupLinesMax(text, maxPerLine){
  const counts = new Map();
  const out = [];
  let removed = 0;
  const lines = s(text).replace(/\r\n/g,'\n').split('\n');

  for (const line of lines) {
    const key = line.trim().replace(/\s+/g,' ');
    if (!key) { out.push(line); continue; }
    const c = counts.get(key) || 0;
    if (c >= maxPerLine) { removed++; continue; }
    counts.set(key, c + 1);
    out.push(line);
  }
  return { text: out.join('\n'), removed };
}

function clipHeadTail(text, maxChars){
  const t = s(text);
  if (t.length <= maxChars) return t;
  if (maxChars <= 0) return '';

  const sep = '\n[n8n] . TRUNCATED (head+tail) .\n';
  const sepLen = sep.length;
  const headLen = Math.max(0, Math.floor((maxChars - sepLen) * 0.65));
  const tailLen = Math.max(0, maxChars - sepLen - headLen);

  if (tailLen <= 0) return t.slice(0, Math.max(0, maxChars - 30)) + '\n[n8n] TRUNCATED';
  return t.slice(0, headLen) + sep + t.slice(Math.max(0, t.length - tailLen));
}

function fileExists(p){ try { return !!p && fs.existsSync(p) && fs.statSync(p).isFile(); } catch { return false; } }

function readHeadTail(fp, headChars, tailChars){
  try {
    const st = fs.statSync(fp);
    const size = st.size;

    const fd = fs.openSync(fp, 'r');
    try {
      const h = Buffer.alloc(Math.min(headChars, size));
      fs.readSync(fd, h, 0, h.length, 0);
      const head = h.toString('utf8');

      if (size <= headChars + tailChars) return head;

      const t = Buffer.alloc(Math.min(tailChars, size));
      fs.readSync(fd, t, 0, t.length, Math.max(0, size - t.length));
      const tail = t.toString('utf8');

      return head + '\n[n8n] ... TRUNCATED ...\n' + tail;
    } finally {
      fs.closeSync(fd);
    }
  } catch {
    return '';
  }
}

const CTX_TOKENS = Number($env.LOGPARSER_NUM_CTX_TOKENS || 128000);
const TOKEN_CHARS = Number($env.LOGPARSER_TOKEN_CHARS || 4);
const MAX_CTX_CHARS = CTX_TOKENS * TOKEN_CHARS;

const MAX_EXAMPLES_PER_NOMINAL = Number($env.LOGPARSER_MAX_EXAMPLES_PER_NOMINAL || 3);
const MAX_REPEAT = Number($env.LOGPARSER_MAX_REPEAT_LINES || 3);

const confirmed = Array.isArray(base.confirmed_events) ? base.confirmed_events : [];
const dgHits = Array.isArray(base.dgA01_hits) ? base.dgA01_hits : [];

function sevRank(sev) {
  const t = s(sev).toLowerCase();
  if (t.includes('crit')) return 4;
  if (t.includes('maj')) return 3;
  if (t.includes('warn')) return 2;
  return 1;
}

// 1) Bucket by phrase+nominal+component
const buckets = new Map();
for (const e of confirmed) {
  const phrase = s(e.phrase || e.term || '').trim() || 'N/A';
  const nominal = s(e.nominal || '').trim() || 'N/A';
  const comp = s(e.component || '').trim() || 'Other';
  const key = `${phrase}||${nominal}||${comp}`;
  if (!buckets.has(key)) buckets.set(key, []);
  buckets.get(key).push(e);
}

// 2) Build compact evidence lines
const blocks = [];
for (const arr of buckets.values()) {
  const sorted = arr.slice().sort((a,b) => sevRank(b.severity) - sevRank(a.severity));
  const limited = sorted.slice(0, MAX_EXAMPLES_PER_NOMINAL);

  for (const e of limited) {
    const line =
      `ts=${s(e.timestamp || 'N/A')}; ` +
      `sev=${s(e.severity || 'N/A')}; ` +
      `comp=${s(e.component || 'N/A')}; ` +
      `nominal=${s(e.nominal || 'N/A')}; ` +
      `code=${s(e.phrase || e.term || 'N/A')}; ` +
      `source=${s(e.source || 'N/A')}:${s(e.line || 'N/A')}; ` +
      `msg=${s(e.evidence || e.lineText || '').replace(/\s+/g, ' ').slice(0, 700)}`;
    blocks.push(line);
  }
}

// 3) dgA01 evidence first
const dgBlock = dgHits.slice(0, 5).map(h =>
  `DG: ${s(h.evidence || '').replace(/\s+/g, ' ').slice(0, 900)} ` +
  `[${s(h.source || 'N/A')}:${s(h.line || 'N/A')}]`
);

// 4) Fallback raw digest excerpt if matcher produced nothing
let fallbackDigest = '';
const digestPath = s(base.digest_errors_path || base.llm5_candidates_path).trim();
if (!blocks.length && !dgBlock.length && fileExists(digestPath)) {
  fallbackDigest = readHeadTail(digestPath, 120000, 80000);
}

// 5) Compose evidence text
let evidenceText = '';
if (dgBlock.length || blocks.length) {
  evidenceText = [dgBlock.join('\n'), blocks.join('\n')].filter(Boolean).join('\n').trim();
} else if (fallbackDigest) {
  evidenceText = `[n8n] MATCHER EMPTY, using raw digest excerpt\n${fallbackDigest}`.trim();
} else {
  evidenceText = '';
}

const HEADER = 'Timestamp;Severity;Component;CodeOrPhrase;Message;Source;KB';

const vendor = s(base.hw_vendor || base.vendor || '').trim() || 'N/A';
const klass  = s(base.hw_class || base.klass || base.class || '').trim() || 'N/A';
const modelHw = s(base.hw_model || base.modelDetected || base.model || '').trim() || 'N/A';

function buildPrompt(ev) {
  return `TASK: STORAGE / ERRORS (SECTION 4 ONLY)

OUTPUT STRICT:
TABLE: Errors
${HEADER}
<rows OR N/A>

RULES:
- semicolon ";" delimiter
- Output ONLY the table, no markdown and no comments
- Each nominal error only once (use most representative line)
- If dgA01 quarantine/fault/offline exists -> FIRST ROW must summarize it
- Evidence-first, do NOT invent
- NEWEST -> OLDEST
- If no real errors -> print header + single row "N/A"

CONTEXT (do NOT echo):
vendor=${vendor}
class=${klass}
model=${modelHw}

EVIDENCE:
${ev || '[NO EVIDENCE]'}`.trim();
}

let llmInput = buildPrompt(evidenceText);
let fitMode = 'raw';
let dedupRemoved = 0;

if (llmInput.length > MAX_CTX_CHARS) {
  const r = dedupLinesMax(evidenceText, MAX_REPEAT);
  evidenceText = r.text.trim();
  dedupRemoved = r.removed;
  fitMode = 'dedup';
  llmInput = buildPrompt(evidenceText);
}

if (llmInput.length > MAX_CTX_CHARS) {
  const overhead = llmInput.length - evidenceText.length;
  const budget = Math.max(0, MAX_CTX_CHARS - overhead - 2000);
  evidenceText = clipHeadTail(evidenceText, budget).trim();
  fitMode = 'clip_head_tail';
  llmInput = buildPrompt(evidenceText);
}

const evidencePath = writeTextFile(base, 'llm5_errors_evidence', evidenceText);
const inputPath = writeTextFile(base, 'llm5_errors_input', llmInput);

const model =
  s(base.ReportLLM).trim() ||
  s(base.model).trim() ||
  s($env.LOGPARSER_REPORT_LLM).trim() ||
  'deepseek-logs:latest';

return [{
  json: {
    ...base,
    task: 'storage_errors',
    taskOrder: 5,
    model,

    // file-based flow (tiny execution)
    llm_input: '',
    messages: [],

