  }
}];

// Build Identify Pack — FULL REPLACE v6.2 (less noise; stronger storage anchors)
// Changes vs v6.1:
// - default MAX_SNIPPET_CHARS: 450000
// - default MAX_MATCHES: 600
// - adds a few storage anchors to KEYWORDS/STRONG

const fs = require('fs');
const path = require('path');

const base = $input.item.json || {};
const s = (x) => (x == null ? '' : String(x));

function fileSizeSafe(fp) { try { return fs.statSync(fp).size; } catch { return 0; } }

const combinedPath = s(base.combinedLogPath).trim();
if (!combinedPath) {
  return [{ json: { ...base, _identify_pack_ok: false, _identify_pack_error: 'combinedLogPath is empty' } }];
}
if (!fs.existsSync(combinedPath)) {
