}

const OUT_DIR = (s($env.ULC_OUT_ROOT).trim() || path.dirname(combinedPath));
const safeBaseName =
  (s(base.archiveName).trim() || s(base.sourceFileName).trim() || path.basename(combinedPath, path.extname(combinedPath)) || 'identify')
    .replace(/[^\w.\-()+ ]+/g, '_')
    .slice(0, 120);

const snippetName = `${safeBaseName}__LLM1_identify_snippet.txt`;
const snippetPath = path.join(OUT_DIR, snippetName);

const KEYWORDS = [
  'dell', 'emc', 'powervault', 'power vault', 'me4', 'me5', 'me4012', 'me4024', 'me4084',
  'manufacturer', 'vendor', 'model', 'product', 'product-id', 'product_id', 'productid',
