  'firmware', 'cpld', 'midplane', 'serial', 'part', 'fru',

  // class anchors
  'storage', 'raid', 'disk group', 'vdisk', 'virtual disk', 'pool', 'sas', 'iscsi', 'fc',
  'volume', 'volumes', 'lun', 'luns',

  // XML anchors
  '<?xml', '<log', '<entry', '<event', '<product', '<system', '<device', '<manufacturer', '<vendor', '<model',
].map(x => String(x).toLowerCase());

const STRONG = [
  'me4012', 'powervault', 'dell', 'emc',
  'enclosure', 'controller', 'disk group', 'vdisk', 'virtual disk', 'pool', 'iscsi', 'fc', 'raid',
  'product', 'model', 'vendor', 'manufacturer',
  'firmware', 'cpld', 'midplane', 'serial'
].map(x => String(x).toLowerCase());

const MAX_SNIPPET_CHARS = Number($env.IDENTIFY_SNIPPET_MAX_CHARS || 450000);
const CONTEXT_LINES_BEFORE = Number($env.IDENTIFY_SNIPPET_CTX_BEFORE || 2);
const CONTEXT_LINES_AFTER  = Number($env.IDENTIFY_SNIPPET_CTX_AFTER || 4);
const MAX_MATCHES = Number($env.IDENTIFY_SNIPPET_MAX_MATCHES || 600);

const ANCHOR_HEAD = Number($env.IDENTIFY_ANCHOR_HEAD_CHARS || 120000);
const ANCHOR_TAIL = Number($env.IDENTIFY_ANCHOR_TAIL_CHARS || 80000);

function splitIntoLinesWithXmlFallback(text, carryRef) {
  let buf = carryRef.carry + text;
  const lines = [];

  const parts = buf.split(/\r?\n/);
  carryRef.carry = parts.pop() || '';
  for (const p of parts) lines.push(p);

  const MAX_CARRY = 2 * 1024 * 1024;
  while (carryRef.carry.length > MAX_CARRY) {
    const slice = carryRef.carry.slice(0, MAX_CARRY);
    const cut = slice.lastIndexOf('>');
    const take = (cut > 0) ? cut + 1 : MAX_CARRY;
    lines.push(carryRef.carry.slice(0, take));
    carryRef.carry = carryRef.carry.slice(take);
  }

  return lines;
}

async function buildSnippetFromHugeFile(srcPath, dstPath) {
  const fd = fs.openSync(dstPath, 'w');
  let written = 0;

  const prev = [];
  let afterCountdown = 0;
  let matches = 0;

  function writeLine(line) {
    if (line == null) return true;
    let x = String(line);
    if (!x.endsWith('\n')) x += '\n';
    const add = x.length;
    if (written + add > MAX_SNIPPET_CHARS) return false;
    fs.writeSync(fd, x);
    written += add;
    return true;
  }

  function hitLine(line) {
    const low = String(line || '').toLowerCase();
    if (!low) return false;
    for (const k of STRONG) if (low.includes(k)) return true;
    for (const k of KEYWORDS) if (low.includes(k)) return true;
    return false;
  }

  function pushPrev(line) {
    prev.push(line);
    if (prev.length > CONTEXT_LINES_BEFORE) prev.shift();
  }

  writeLine(`TASK CONTEXT (LLM1 IDENTIFY)\n- Source: ${srcPath}\n- archiveName: ${s(base.archiveName).trim()}\n- sourceFileName: ${s(base.sourceFileName).trim()}\n- combinedLogBytes: ${s(base.combinedLogBytesWritten)}\n`);
  writeLine('--- BEGIN IDENTIFY EVIDENCE ---\n');

  // HEAD anchor
  try {
    const fdH = fs.openSync(srcPath, 'r');
    const b = Buffer.alloc(Math.max(0, ANCHOR_HEAD));
    const n = fs.readSync(fdH, b, 0, b.length, 0);
    fs.closeSync(fdH);
    const headText = b.slice(0, n).toString('utf8');
    writeLine('=== ANCHOR: FILE HEAD ===');
    writeLine(headText);
    writeLine('=== END ANCHOR: FILE HEAD ===\n');
  } catch {}

  await new Promise((resolve, reject) => {
    const rs = fs.createReadStream(srcPath, { highWaterMark: 256 * 1024 });
    const carryRef = { carry: '' };

    rs.on('data', (chunk) => {
      const txt = chunk.toString('utf8');
      const lines = splitIntoLinesWithXmlFallback(txt, carryRef);

      for (const rawLine of lines) {
        const line = rawLine;

        pushPrev(line);

        if (hitLine(line) && matches < MAX_MATCHES) {
          matches++;
          if (!writeLine('\n===== HIT =====')) { rs.destroy(); break; }
          for (const b of prev) {
            if (!writeLine(`[ctx-] ${b}`)) { rs.destroy(); break; }
          }
          if (!writeLine(`[hit] ${line}`)) { rs.destroy(); break; }
          afterCountdown = CONTEXT_LINES_AFTER;
          continue;
        }

        if (afterCountdown > 0) {
          if (!writeLine(`[ctx+] ${line}`)) { rs.destroy(); break; }
          afterCountdown--;
        }

        if (written >= MAX_SNIPPET_CHARS) { rs.destroy(); break; }
      }
    });

    rs.on('end', () => {
      try {
        if (carryRef.carry && written < MAX_SNIPPET_CHARS) {
          writeLine('\n===== TAIL CARRY =====');
          writeLine(carryRef.carry.slice(0, 120000));
        }
      } catch {}
      resolve();
    });

    rs.on('error', reject);
    rs.on('close', resolve);
  });

  // TAIL anchor
  try {
    const st = fs.statSync(srcPath);
    const start = Math.max(0, st.size - ANCHOR_TAIL);
    const fdT = fs.openSync(srcPath, 'r');
    const b = Buffer.alloc(Math.max(0, ANCHOR_TAIL));
    const n = fs.readSync(fdT, b, 0, b.length, start);
    fs.closeSync(fdT);
    const tailText = b.slice(0, n).toString('utf8');
    writeLine('\n=== ANCHOR: FILE TAIL ===');
    writeLine(tailText);
    writeLine('=== END ANCHOR: FILE TAIL ===\n');
  } catch {}

  writeLine('\n--- END IDENTIFY EVIDENCE ---\n');
  fs.closeSync(fd);

  return { writtenChars: written, matches };
}

const identifyModel =
  s(base.identify_model).trim() ||
  s($env.IDENTIFY_MODEL).trim() ||
  s(base.ReportLLM).trim() ||
  'qwen2.5:32b-instruct-q8_0';

const hints = [
