// Parse Identify Result — FULL REPLACE v5.5 (fallback heuristics when JSON/schema breaks)

const fs = require('fs');

const base = $input.item.json || {};
const s = (x) => (x == null ? '' : String(x));

function stripFences(t) {
  const m = s(t).match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  return (m ? m[1] : s(t)).trim();
}

function firstJsonObject(text) {
  const t = stripFences(text);
  const start = t.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  for (let i = start; i < t.length; i++) {
    const ch = t[i];
    if (ch === '{') depth++;
    if (ch === '}') {
      depth--;
      if (depth === 0) {
        const block = t.slice(start, i + 1);
        try { return JSON.parse(block); } catch { return null; }
      }
    }
  }
  return null;
}

function normNA(x) {
  const v = s(x).trim();
  if (!v) return 'N/A';
  const low = v.toLowerCase();
  if (['na','n/a','none','null','unknown','-'].includes(low)) return 'N/A';
  return v;
}

function normVendor(x) {
  const v = normNA(x);
  if (v === 'N/A') return 'N/A';
  const low = v.toLowerCase();
  if (low.includes('dell') || low.includes('emc')) return 'Dell EMC';
  if (low.includes('hpe') || low.includes('hewlett')) return 'HPE';
  if (low.includes('lenovo')) return 'Lenovo';
  if (low.includes('netapp')) return 'NetApp';
  if (low.includes('cisco')) return 'Cisco';
  if (low.includes('huawei')) return 'Huawei';
  if (low.includes('ibm')) return 'IBM';
  if (low === 'other') return 'Other';
  return 'Other';
}

function normClass(x) {
  const v = normNA(x);
  if (v === 'N/A') return 'N/A';
  const low = v.toLowerCase();
  if (low === 'storage') return 'Storage';
  if (low === 'server') return 'Server';
  if (low === 'switch') return 'Switch';
  if (low === 'ups') return 'UPS';
  if (low === 'other') return 'Other';
  if (low.includes('stor')) return 'Storage';
  if (low.includes('swit')) return 'Switch';
  if (low.includes('serv')) return 'Server';
  return 'Other';
}

function better(current, candidate, { allowOther=false } = {}) {
  const cur = normNA(current);
  const cand = normNA(candidate);
  if (cand === 'N/A') return cur;
  if (!allowOther && cand === 'Other') return cur;
  if (cur === 'N/A') return cand;
  if (!allowOther && cur === 'Other') return cand;
  return cur;
}

function extractRaw() {
  const prefer = [
    base.identify_raw,
    base.ollama_text,
    base.ollama?.message?.content,
    base.ollama?.response,
    base.message?.content,
    base.text,
  ];
  for (const x of prefer) {
    const t = s(x).trim();
    if (t) return t;
  }
  return '';
}

function safeReadHead(fp, maxChars) {
  try { return fs.readFileSync(fp).toString('utf8').slice(0, maxChars); } catch { return ''; }
}

function heuristicFromText(text) {
  const t = s(text);
  const low = t.toLowerCase();

  // Vendor
  let vendor = 'N/A';
  if (low.includes('dell') || low.includes('emc') || low.includes('powervault') || low.includes('power vault')) vendor = 'Dell EMC';
  else if (low.includes('hpe') || low.includes('hewlett')) vendor = 'HPE';
  else if (low.includes('lenovo')) vendor = 'Lenovo';
  else if (low.includes('netapp')) vendor = 'NetApp';
  else if (low.includes('cisco')) vendor = 'Cisco';
  else if (low.includes('huawei')) vendor = 'Huawei';
  else if (low.includes('ibm')) vendor = 'IBM';

  // Model (ME4/ME5 etc)
  let model = 'N/A';
  const m1 = t.match(/\bME\d{3,5}\b/i);
  if (m1) model = m1[0].toUpperCase();
  const m2 = t.match(/PowerVault\s+(ME\d{3,5})/i);
  if (m2) model = m2[1].toUpperCase();

  // Class
  let klass = 'N/A';
  const storageSignals = [
    'powervault','me4','me5','enclosure','controller','disk group','vdisk','virtual disk','pool','iscsi','fc','raid'
  ];
  if (storageSignals.some(k => low.includes(k))) klass = 'Storage';

  // confidence
  let conf = 20;
  if (vendor !== 'N/A') conf += 25;
  if (model !== 'N/A') conf += 25;
  if (klass !== 'N/A') conf += 20;
  if (conf > 90) conf = 90;

  return { vendor, klass, model, confidence: conf };
}

const raw = extractRaw();

// 1) try JSON first
const j = firstJsonObject(raw) || {};

let vendor = normVendor(j.vendor ?? j.manufacturer ?? j.hw_vendor);
let klass  = normClass(j.class ?? j.klass ?? j.hw_class);
let model  = normNA(j.model ?? j.hw_model ?? j.product_id ?? j.productId);
let product_name = normNA(j.product_name ?? j.productName ?? j.name ?? j.array_name);

let confidence = Number(j.confidence);
if (!Number.isFinite(confidence)) confidence = (vendor !== 'N/A' && klass !== 'N/A') ? 70 : 35;

// 2) if schema broken -> heuristic fallback from raw + snippet head
const schemaLooksBroken = !j || typeof j !== 'object' || Array.isArray(j) || !('vendor' in j) || !('class' in j) || !('model' in j);
if (schemaLooksBroken || vendor === 'N/A' || klass === 'N/A' || model === 'N/A') {
  const snippetPath = s(base.identify_snippet_path).trim();
  const snippetHead = snippetPath ? safeReadHead(snippetPath, 60000) : '';
  const h = heuristicFromText(raw + '\n' + snippetHead);

  vendor = better(vendor, h.vendor, { allowOther: true });
  klass  = better(klass,  h.klass,  { allowOther: false });
  model  = better(model,  h.model,  { allowOther: true });

  if (!Number.isFinite(confidence) || confidence <= 35) confidence = Math.max(confidence || 0, h.confidence);
}

// 3) RAG hints: only fill gaps
vendor = better(vendor, base.rag_identify_vendor, { allowOther: true });
klass  = better(klass,  base.rag_identify_klass || base.rag_identify_class, { allowOther: false });
model  = better(model,  base.rag_identify_model, { allowOther: true });

// 4) Explicit overrides (only if meaningful)
vendor = better(vendor, base.vendor, { allowOther: true });
klass  = better(klass,  base.klass,  { allowOther: false });
model  = better(model,  base.modelDetected, { allowOther: true });

const identify_ok = (vendor !== 'N/A') && (klass !== 'N/A') && (klass !== 'Other');

return [{
  json: {
    ...base,

    vendor,
    klass,
    modelDetected: model,
    productNameDetected: product_name,
    confidence,

    hw_vendor: vendor,
    hw_class: klass,
    hw_model: model,
    hw_product_name: product_name,

    identify_raw: raw,
    identify_confidence: confidence,
    _identify_ok: identify_ok,
  }
}];

/**
 * LLM Request Identify — FULL REPLACE v4.3 (validate + retry + evidence clamp)
 * Goal:
 * - Force exact schema (5 keys) with retries if model drifts
