const fs = require('fs');

const base = $json || {};
const OLLAMA = String($env.OLLAMA_URL || 'http://127.0.0.1:11434').replace(/\/+$/, '');
const url = `${OLLAMA}/api/chat`;

function s(v, d='') { return (v===undefined || v===null) ? d : String(v); }

function maskPII(t) {
  let x = s(t);
  x = x.replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig, '<email>');
  x = x.replace(/(?:\+?\d[\d\s\-()]{7,}\d)/g, '<phone>');
  return x;
}

function safeReadAll(fp) {
  try { return fs.readFileSync(fp).toString('utf8'); } catch { return ''; }
}

function stripFences(t) {
  const m = s(t).match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  return (m ? m[1] : s(t)).trim();
}

function firstJsonObject(text) {
  const t = stripFences(text);
  const start = t.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  for (let i = start; i < t.length; i++) {
    const ch = t[i];
    if (ch === '{') depth++;
    if (ch === '}') {
      depth--;
      if (depth === 0) {
        const block = t.slice(start, i + 1);
        try { return JSON.parse(block); } catch { return null; }
      }
    }
  }
  return null;
}

function normalizeVendor(v) {
  const x = s(v).trim();
  const low = x.toLowerCase();
  if (!x) return 'N/A';
  if (low === 'dell' || low.includes('dell emc') || low.includes('emc')) return 'Dell EMC';
  if (low.includes('hpe') || low.includes('hewlett')) return 'HPE';
  if (low.includes('lenovo')) return 'Lenovo';
  if (low.includes('netapp')) return 'NetApp';
  if (low.includes('cisco')) return 'Cisco';
  if (low.includes('huawei')) return 'Huawei';
  if (low.includes('ibm')) return 'IBM';
  if (low === 'other') return 'Other';
  if (low === 'n/a' || low === 'na' || low === 'unknown') return 'N/A';
  // if not in allowlist -> Other (schema allows Other)
  return 'Other';
}

function normalizeClass(c) {
  const x = s(c).trim();
  const low = x.toLowerCase();
  if (!x) return 'N/A';
  if (low.includes('stor')) return 'Storage';
  if (low.includes('serv')) return 'Server';
  if (low.includes('swit')) return 'Switch';
  if (low.includes('ups')) return 'UPS';
  if (low === 'other') return 'Other';
  if (low === 'n/a' || low === 'na' || low === 'unknown') return 'N/A';
  return 'Other';
}

function clampEvidence(text, headChars = 140000, tailChars = 40000) {
  const t = s(text);
  if (t.length <= headChars + tailChars + 2000) return t;
  const head = t.slice(0, headChars);
  const tail = t.slice(-tailChars);
  return `${head}\n\n[...EVIDENCE CLAMPED...]\n\n${tail}`;
}

function validateSchema(obj) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return { ok: false, why: 'not_object' };

  const keys = Object.keys(obj);
  const expected = ['vendor','class','model','confidence','evidence'];
  if (keys.length !== expected.length) return { ok: false, why: `keys_len_${keys.length}` };
  for (const k of expected) if (!keys.includes(k)) return { ok: false, why: `missing_${k}` };
  for (const k of keys) if (!expected.includes(k)) return { ok: false, why: `extra_${k}` };

  const vendor = normalizeVendor(obj.vendor);
  const klass  = normalizeClass(obj.class);
  const model  = s(obj.model).trim() || 'N/A';

  const conf = Number(obj.confidence);
  if (!Number.isFinite(conf) || conf < 0 || conf > 100) return { ok: false, why: 'bad_confidence' };

  if (!Array.isArray(obj.evidence)) return { ok: false, why: 'evidence_not_array' };
  if (obj.evidence.length > 5) return { ok: false, why: 'evidence_too_many' };

  // force normalization
  obj.vendor = vendor;
  obj.class = klass;
  obj.model = model === '' ? 'N/A' : model;

  // if any essential is N/A -> confidence should be <= 40 (per rule)
  const essentialMissing = (obj.vendor === 'N/A' || obj.class === 'N/A' || obj.model === 'N/A');
  if (essentialMissing && conf > 40) return { ok: false, why: 'conf_too_high_for_na' };

  return { ok: true, why: '' };
}

function prune(out) {
  const drop = [
    'messages','llm_input','chatInput','prompt',
    'identify_prompt','identify_evidence_text','identify_evidence_inline',
    'docs_context','event_catalog_context',
    'logsCombined','combinedLogs','logDigest','logDigestText',
    'error_candidates_text','errors_index_text',
  ];
  for (const k of drop) if (k in out) delete out[k];
  return out;
}

async function ollamaChat(model, system, user, formatJson) {
  const payload = {
    model,
    stream: false,
    format: formatJson ? 'json' : undefined,
    messages: [
      { role: 'system', content: system },
      { role: 'user', content: user },
    ],
    options: { temperature: 0, top_p: 1, top_k: 1 },
  };

  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: { 'Content-Type': 'application/json' },
    body: payload,
    json: true,
    timeout: 60 * 60 * 1000,
  });

  const txt =
    (resp && resp.message && typeof resp.message.content === 'string') ? resp.message.content :
    (resp && typeof resp.response === 'string') ? resp.response :
    JSON.stringify(resp);

  return { resp, txt };
}

async function main() {
  const model = s(base.identify_model) || s(base.ReportLLM) || s($env.IDENTIFY_MODEL) || 'qwen2.5:32b-instruct-q8_0';
  const hints = s(base.identify_hints).trim();

  const snippetPath = s(base.identify_snippet_path).trim();
  if (!snippetPath) {
    const out = { ...base };
    out.identify_raw = '';
    out.ollama_text = '';
    out._identify_llm_ok = false;
    out._identify_llm_error = 'identify_snippet_path is empty';
    prune(out);
    return [{ json: out }];
  }

  let evidence = safeReadAll(snippetPath);
  evidence = maskPII(evidence);
  evidence = clampEvidence(evidence, Number($env.IDENTIFY_EVIDENCE_HEAD || 140000), Number($env.IDENTIFY_EVIDENCE_TAIL || 40000));

  const ragCtx = s(base.rag_identify_context).trim();
  const ragBlock = ragCtx ? `\nOFFLINE DOCS CONTEXT (RAG, short):\n${ragCtx}\n` : '';

  const system = `ROLE: LOGPARSER IDENTIFY (NOT A CHATBOT)
You MUST output ONLY one JSON object, and it MUST match the schema EXACTLY.
NO extra keys. NO explanations. NO markdown.`;

  const schema = `JSON SCHEMA (exact keys only):
{
  "vendor": "N/A|Dell EMC|HPE|IBM|Huawei|NetApp|Cisco|Lenovo|Other",
  "class": "Storage|Server|Switch|UPS|Other",
  "model": "string or N/A",
  "confidence": 0-100,
  "evidence": ["up to 5 short quotes copied from EVIDENCE"]
}

HARD RULES:
- If vendor/class/model are not explicitly present in EVIDENCE -> set that field to "N/A" and confidence <= 40.
- Prefer "Storage" if ANY evidence mentions: enclosure/controller/disk group/vdisk/virtual disk/pool/iSCSI/FC/RAID/PowerVault/ME4/ME5.
- Evidence must be short literal quotes from EVIDENCE (verbatim fragments).
- Output MUST be a single JSON object with ONLY these 5 keys.`;

  const example = `EXAMPLE OUTPUT:
{"vendor":"Dell EMC","class":"Storage","model":"ME4012","confidence":92,"evidence":["PowerVault ME4012","Vendor: Dell EMC","Model: ME4012"]}`;

  const baseUser = `TASK: IDENTIFY HARDWARE (LLM1)

${schema}

${example}

HINTS:
${hints}

EVIDENCE:
${evidence}
${ragBlock}
`;

  const attempts = [];
  let lastTxt = '';
  let lastObj = null;
  let lastWhy = '';

  for (let i = 1; i <= 3; i++) {
    const user = (i === 1)
      ? baseUser
      : `REPAIR OUTPUT (attempt ${i})
Your previous output did NOT match the schema (${lastWhy}).
Return ONLY valid JSON with EXACT keys: vendor,class,model,confidence,evidence.
No extra keys.

PREVIOUS OUTPUT:
${lastTxt}

NOW RETURN ONLY THE FIXED JSON OBJECT.`;

    const { resp, txt } = await ollamaChat.call(this, model, system, user, true);
    lastTxt = s(txt).trim();

    const obj = firstJsonObject(lastTxt);
    const v = obj ? validateSchema(obj) : { ok: false, why: 'no_json_object' };

    attempts.push({
      i,
      ok: v.ok,
      why: v.why,
      txt_head: lastTxt.slice(0, 220),
    });

    if (v.ok) {
      lastObj = obj;
      break;
    }
    lastWhy = v.why;
  }

  const out = { ...base };

  out.ollama = { model, done_reason: 'stop' };
  out.identify_runtime = {
    snippet_path: snippetPath,
    snippet_chars_used: evidence.length,
    rag_ctx_chars: ragCtx.length,
    attempts,
  };

  if (lastObj) {
    out.identify_raw = JSON.stringify(lastObj);
    out.ollama_text = out.identify_raw;
    out._identify_llm_ok = true;
    out._identify_llm_error = '';
  } else {
