}

return await main();

// Ingest Attachments (Universal) — FULL REPLACE v3-universal-pick
// Goal:
// - pick "main" non-image attachment deterministically
// - normalize archiveName/sourceFileId/sourceFileName
// - do NOT download here (Universal Log Collector will download+unpack)
// Output fields (contract):
//   sourceFileId, sourceFileName, archiveName, archiveExt, _ingest_debug

function s(x){ return x == null ? '' : String(x); }

function isImageFile(f){
  const kind = s(f?.kind).toLowerCase();
  if (kind === 'image') return true;
  const name = s(f?.name).toLowerCase();
  return /\.(png|jpg|jpeg|webp|bmp|tiff|gif)$/i.test(name);
}

function extLower(name){
  const n = s(name).trim().toLowerCase();
  const just = n.split(/[\\/]/).pop();
  const multi = ['.tar.gz','.tgz','.tar.bz2','.tbz2','.tar.xz','.txz','.tar.zst'];
  for (const m of multi) if (just.endsWith(m)) return m;
  const m2 = just.match(/(\.[a-z0-9]+)$/i);
  return m2 ? m2[1].toLowerCase() : '';
}

function scoreAttachment(f){
  const name = s(f?.name).toLowerCase();
  const ext = extLower(name);

  let sc = 0;
  if (['.zip','.tar.gz','.tgz','.tar','.gz','.tbz2','.tar.bz2','.bz2','.xz','.tar.xz','.txz','.7z','.zst','.tar.zst'].includes(ext)) sc += 200;
  if (/\.(log|txt|csv|xml|json|yml|yaml|cfg|conf|ini|out|err)$/i.test(name)) sc += 40;

  const size = Number(f?.size);
  if (Number.isFinite(size) && size > 0) sc += Math.min(80, Math.floor(size / 10_000_000));

  const fid = s(f?.file_id || f?.id);
  if (fid.startsWith('disk/')) sc += 10;

  return sc;
}

const base = $input.item.json || {};
const files = Array.isArray(base.files) ? base.files : [];

const nonImage = files.filter(f => !isImageFile(f));
let chosen = null;

// 1) if Prepare prompt already set sourceFileId/sourceFileName — trust it
const preId = s(base.sourceFileId).trim();
if (preId) {
  chosen = nonImage.find(f => s(f.file_id || f.id).trim() === preId) || null;
}

// 2) else pick best-scored non-image
if (!chosen && nonImage.length) {
  chosen = nonImage
    .slice()
    .sort((a,b)=> scoreAttachment(b) - scoreAttachment(a))[0] || null;
}

// 3) fallback: any file
if (!chosen && files.length) chosen = files[0];

const sourceFileId = chosen ? s(chosen.file_id || chosen.id).trim() : '';
const sourceFileName = chosen ? s(chosen.name).trim() : '';

const archiveName = sourceFileName || s(base.archiveName).trim() || 'attachment';
const archiveExt = extLower(archiveName);

return [{
  json: {
    ...base,

    sourceFileId,
    sourceFileName,

    archiveName,
    archiveExt,

    _ingest_debug: {
      files_total: files.length,
      non_image_total: nonImage.length,
      chosen: chosen ? {
        file_id: s(chosen.file_id || chosen.id),
        name: s(chosen.name),
        size: Number(chosen.size || 0) || 0,
        ext: archiveExt,
        score: scoreAttachment(chosen),
      } : null
    }
  }
}];

