const query = (seed + '\n' + head).replace(/\s+/g, ' ').trim().slice(0, 800) || seed || 'hardware identify';

async function main() {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${RAG}/search/all`,
      json: true,
      timeout: TIMEOUT,
