      if (fn || ex) ctxLines.push(`DOC: ${fn} ${page} :: ${ex}`);
    }
    for (const e of ev.slice(0, 6)) {
      const vendor = s(e.vendor).trim();
      const klass = s(e.class || e.klass).trim();
      const model = s(e.model).trim();
      const phrase = s(e.phrase || e.text || '').replace(/\s+/g, ' ').trim().slice(0, 180);
      ctxLines.push(`CAT: ${vendor}/${klass}/${model} :: ${phrase}`);
    }

    const top = ev[0] || {};
    return [{
      json: {
        ...base,
        rag_identify_vendor: s(top.vendor).trim(),
        rag_identify_klass: s(top.class || top.klass).trim(),
        rag_identify_model: s(top.model).trim(),
