// LLM Request Storage Disk — FULL REPLACE v6.3-strict-table-file
// FIX:
// - Always read prompt from llm3_input_path (if exists)
// - Force strict table-only response with SYSTEM lock
// - Force num_ctx=131072 (default) to avoid 32K clipping
// - Strip <think> and normalize output to TABLE: Disks
// - Prune heavy fields from execution payload

const fs = require('fs');

const base = $input.item.json || $json || {};

function s(x) { return x == null ? '' : String(x); }

const OLLAMA_URL = s($env.OLLAMA_URL || 'http://10.10.200.9:11434').replace(/\/+$/, '');
const url = `${OLLAMA_URL}/api/chat`;

const DEFAULT_HEADER = 'enclosure_id;slot;disk_id;serial_number;part_number;model;vendor;size_gb;type;speed_rpm;state;health;firmware';

function safeReadUtf8(fp) {
  try {
    if (!fp) return '';
    if (!fs.existsSync(fp)) return '';
    return fs.readFileSync(fp, 'utf8');
  } catch {
    return '';
  }
}

function stripThink(text) {
  let t = s(text);
  // remove <think>...</think> blocks (including multiline)
  t = t.replace(/<think\b[^>]*>[\s\S]*?<\/think>/gi, '');
  // safety: if model emits unmatched <think>, trim from it
  t = t.replace(/<think\b[^>]*>[\s\S]*$/gi, '');
  return t;
}

function stripCodeFences(text) {
  let t = s(text).trim();

  // If wrapped in fenced block, extract inner content
  const fenced = t.match(/```(?:[a-zA-Z0-9_-]+)?\s*([\s\S]*?)```/);
  if (fenced) t = s(fenced[1]).trim();

  // Remove any stray fence lines
  t = t.replace(/^\s*```.*$/gm, '').trim();

  return t;
}

function normalizeDisksOutput(raw) {
  let t = stripCodeFences(stripThink(raw)).replace(/\r/g, '').trim();

  if (!t) return `TABLE: Disks\nN/A`;

  // Try to anchor from TABLE: Disks
  const tableAnchor = t.match(/(^|\n)\s*TABLE:\s*Disks\b/i);
  if (tableAnchor) {
    t = t.slice(tableAnchor.index + (tableAnchor[1] ? tableAnchor[1].length : 0)).trim();
  } else {
    // If no explicit TABLE line, try to anchor from header
    const headerIdx = t.toLowerCase().indexOf(DEFAULT_HEADER.toLowerCase());
    if (headerIdx >= 0) {
      t = 'TABLE: Disks\n' + t.slice(headerIdx).trim();
    } else if (/\bN\/A\b/i.test(t)) {
      return `TABLE: Disks\nN/A`;
    } else {
      // Last resort: keep semicolon-like lines only
      const semis = t.split('\n').map(x => x.trim()).filter(x => x && x.includes(';'));
      if (!semis.length) return `TABLE: Disks\nN/A`;

      const hasHeader = semis.some(x => x.toLowerCase().startsWith('enclosure_id;slot;'));
      t = [
        'TABLE: Disks',
        ...(hasHeader ? [] : [DEFAULT_HEADER]),
        ...semis,
      ].join('\n');
    }
  }

  // Keep only the TABLE: Disks block (drop any extra tables/prose)
  const lines = t.split('\n');
  const out = [];
  let started = false;
  let headerSeen = false;
  let dataSeen = false;

  for (let line of lines) {
    line = s(line).trim();
    if (!line) continue;

    // stop if another table starts
    if (started && /^TABLE:\s*(?!Disks\b)/i.test(line)) break;

    if (!started) {
      if (/^TABLE:\s*Disks\b/i.test(line)) {
        out.push('TABLE: Disks');
        started = true;
      } else if (line.toLowerCase().startsWith('enclosure_id;slot;')) {
        out.push('TABLE: Disks');
        out.push(line);
        started = true;
        headerSeen = true;
      } else if (/^N\/A$/i.test(line)) {
        out.push('TABLE: Disks');
        out.push('N/A');
        started = true;
        dataSeen = true;
      }
      continue;
    }

    if (/^TABLE:\s*Disks\b/i.test(line)) {
      // normalize duplicate table line
      if (!out.length) out.push('TABLE: Disks');
      continue;
    }

    if (/^```/.test(line)) continue;

    if (/^N\/A$/i.test(line)) {
      // keep N/A only if no rows were found
      if (!dataSeen) out.push('N/A');
      dataSeen = true;
      continue;
    }

    // Keep header and semicolon rows only, drop narrative text
    if (line.toLowerCase().startsWith('enclosure_id;slot;')) {
      out.push(DEFAULT_HEADER); // normalize exact header
      headerSeen = true;
      continue;
    }

    if (line.includes(';')) {
      // looks like a table row
      out.push(line);
      dataSeen = true;
      continue;
    }

    // ignore prose like "Based on..." / "Here is..."
  }

  // Finalize
  if (!out.length || out[0] !== 'TABLE: Disks') {
    out.unshift('TABLE: Disks');
  }

  if (!headerSeen) {
    // If table has rows but model forgot header, insert header
    const hasRows = out.some((x) => x.includes(';') && !x.toLowerCase().startsWith('enclosure_id;slot;'));
    const hasNA = out.some((x) => /^N\/A$/i.test(x));
    if (hasRows && !hasNA) out.splice(1, 0, DEFAULT_HEADER);
  }

  // If no data rows and no N/A, force N/A
  const hasAnyRows = out.some((x) => x.includes(';') && !x.toLowerCase().startsWith('enclosure_id;slot;'));
  const hasNA = out.some((x) => /^N\/A$/i.test(x));
  if (!hasAnyRows && !hasNA) {
    return `TABLE: Disks\nN/A`;
  }

  return out.join('\n').trim();
}

function pickMeta(resp) {
  const o = resp || {};
  return {
    model: o.model,
    created_at: o.created_at,
    done: o.done,
    done_reason: o.done_reason,
    total_duration: o.total_duration,
    load_duration: o.load_duration,
    prompt_eval_count: o.prompt_eval_count,
    prompt_eval_duration: o.prompt_eval_duration,
    eval_count: o.eval_count,
    eval_duration: o.eval_duration,
  };
}

function prune(out) {
  const drop = [
    'messages',
    'llm_input',
    'chatInput',
    'prompt',
    'digest_disks_text',
    'disks_digest',
    'disksText',
    'docs_context',
    'event_catalog_context',
    'logsCombined',
    'combinedLogs',
    'logDigest',
    'logDigestText',
  ];
  for (const k of drop) if (k in out) delete out[k];
  return out;
}

async function main() {
  const inputPath = s(base.llm3_input_path).trim();
  const filePrompt = safeReadUtf8(inputPath);
  const fallbackPrompt =
    s(base.llm_input) ||
    s(base.prompt) ||
    s(base.chatInput) ||
    s(base.digest_disks_text) ||
    'TASK: STORAGE / DISKS INVENTORY\nTABLE: Disks\nN/A';

  const userPrompt = s(filePrompt || fallbackPrompt).trim();

  const model =
    s(base.model).trim() ||
    s(base.ReportLLM).trim() ||
    s($env.STORAGE_LLM_MODEL_DISKS).trim() ||
    s($env.STORAGE_LLM_MODEL).trim() ||
    'qwen2.5:32b-instruct-q8_0';

  const STRICT_TABLE_SYSTEM = [
    'ROLE: TABLE EXTRACTOR (NOT A CHATBOT).',
    'Return ONLY the requested disks table.',
    'NO reasoning, NO explanations, NO markdown fences, NO extra text.',
    'If no data exists, return exactly:',
    'TABLE: Disks',
    'N/A',
    'Do not add anything before or after the table.'
  ].join('\n');

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: { 'Content-Type': 'application/json' },
      json: true,
      body: {
        model,
        stream: false,
        messages: [
          { role: 'system', content: STRICT_TABLE_SYSTEM },
          { role: 'user', content: userPrompt },
        ],
        options: {
          temperature: 0,
          top_k: 1,
          top_p: 1,
          num_ctx: Number($env.STORAGE_NUM_CTX || 131072),
          // generous default so large disk tables don't truncate
          num_predict: Number($env.STORAGE_NUM_PREDICT || 24000),
          repeat_penalty: Number($env.STORAGE_REPEAT_PENALTY || 1.05),
        },
      },
      timeout: 60 * 60 * 1000,
    });

    const rawContent =
      (resp && resp.message && typeof resp.message.content === 'string') ? resp.message.content :
      (typeof resp?.response === 'string') ? resp.response :
      JSON.stringify(resp);

    const normalized = normalizeDisksOutput(rawContent);

    const out = {
      ...base,
      model,
      ollama_disks: {
        ...pickMeta(resp),
        // keep small snippet for debug, but not full raw reasoning
        preview: s(rawContent).replace(/\s+/g, ' ').slice(0, 300),
      },
      disks_raw: normalized,
      message: { role: 'assistant', content: normalized },

      _llm3_request_mode: 'file_first_strict_system',
      _llm3_input_source: filePrompt ? 'llm3_input_path' : 'fallback_json',
      _llm3_input_path_ok: !!filePrompt,
      _llm3_input_chars: userPrompt.length,
    };

    prune(out);
    return [{ json: out }];
  } catch (e) {
    const status = e?.response?.status || e?.statusCode || '';
    const data = e?.response?.data ? JSON.stringify(e.response.data).slice(0, 2000) : '';
    const out = {
      ...base,
      model,
      disks_raw: `[LLM3 ERROR] status=${status} ${s(e?.message || e)}`,
      message: { role: 'assistant', content: `[LLM3 ERROR] status=${status} ${s(e?.message || e)}` },
      _llm_error: true,
      _llm_error_status: status,
      _llm_error_data: data,
      _llm3_request_mode: 'file_first_strict_system',
    };
    prune(out);
    return [{ json: out }];
  }
}

return await main();

