  t = t.replace(/<think\b[^>]*>[\s\S]*?<\/think>/gi, '');
  t = t.replace(/<think\b[^>]*>[\s\S]*$/gi, '');
  return t;
}

function stripCodeFences(text) {
  let t = s(text).trim();
  const fenced = t.match(/```(?:[a-zA-Z0-9_-]+)?\s*([\s\S]*?)```/);
  if (fenced) t = s(fenced[1]).trim();
  t = t.replace(/^\s*```.*$/gm, '').trim();
  return t;
}

function normalizeTableName(line){
  const t = s(line).trim();
  if (/^TABLE:\s*PowerSupplies\b/i.test(t)) return 'TABLE: PowerSupplies';
  if (/^TABLE:\s*PSU\b/i.test(t))           return 'TABLE: PowerSupplies';
  if (/^TABLE:\s*Fans?\b/i.test(t))         return 'TABLE: Fans';
  if (/^TABLE:\s*SFP\b/i.test(t))           return 'TABLE: SFP';
  return '';
