function isLikelyDataRow(line){
  const t = s(line).trim();
  if (!t) return false;
  if (/^```/.test(t)) return false;
  if (/^TABLE:/i.test(t)) return false;
  if (/^(here|below|based on|note:|explanation)/i.test(t)) return false;
  return t.includes(';') || /^N\/A$/i.test(t);
