      }
      if (/(^|;)port;.*sfp|supported_speeds|connector_type/.test(low)) {
        sections.SFP.push(line);
        continue;
      }
    }
  }

  // finalize each table
  function finalize(name){
    const rows = sections[name].filter(Boolean);
    const cleaned = [];

    let hasNA = false;
    for (const r of rows) {
      if (/^N\/A$/i.test(r)) { hasNA = true; continue; }
      cleaned.push(r);
    }

    if (!cleaned.length) return [`TABLE: ${name}`, 'N/A'];

    // If model emitted header+rows or only rows, keep as-is (we don't force headers here)
    return [`TABLE: ${name}`, ...cleaned];
  }

  return [
    ...finalize('PowerSupplies'),
    '',
    ...finalize('Fans'),
    '',
    ...finalize('SFP'),
  ].join('\n').trim();
}

function pickMeta(resp) {
  const o = resp || {};
  return {
    model: o.model,
    created_at: o.created_at,
    done: o.done,
    done_reason: o.done_reason,
    total_duration: o.total_duration,
    load_duration: o.load_duration,
    prompt_eval_count: o.prompt_eval_count,
    prompt_eval_duration: o.prompt_eval_duration,
    eval_count: o.eval_count,
    eval_duration: o.eval_duration,
  };
}

function prune(out) {
  const drop = [
    'messages',
    'llm_input',
    'chatInput',
    'prompt',
    'digest_periphery_text',
    'digest_periphery',
    'periphery_digest',
    'docs_context',
    'event_catalog_context',
    'logsCombined',
    'combinedLogs',
    'logDigest',
    'logDigestText',
  ];
  for (const k of drop) if (k in out) delete out[k];
  return out;
}

