// Universal Log Collector — FULL REPLACE v6.8 (accept UTF-16/XML logs with NUL bytes; NO text/file-size limits; disk-only payload; LOGPARSER TOKEN ONLY)
// Fix for store_*.logs (ME4 telemetry XML dumps):
// - Old logic skipped any file containing 0x00 as "binary" -> dropped UTF-16 / padded XML.
// - New logic: detect UTF-16 (BOM or NUL-pattern) and treat as TEXT, not binary.
// - decodeSmart now supports UTF-16LE/UTF-16BE (BOM + heuristic).
//
// Still keeps:
// - ULC_MAX_FILES (default 4000)
// - ULC_MAX_DEPTH (default 10)
// - payload stays tiny (only paths + sizes), no logs in runData
//
// Uses ONLY $env.YANDEX_BOT_TOKEN_LOGPARSER

const https = require('https');
const fs = require('fs');
const path = require('path');
const os = require('os');
const crypto = require('crypto');
const child_process = require('child_process');
const zlib = require('zlib');

const base = $input.item.json || {};
