const MAX_FILES = Number(env.ULC_MAX_FILES || 4000);
const DEBUG_MAX_TRIES = Number(env.ULC_DEBUG_MAX_TRIES || 12);

function s(x) { return x == null ? '' : String(x); }
function ensureDir(p) { fs.mkdirSync(p, { recursive: true }); }
function safeName(name) {
  const t = s(name).trim() || 'attachment.bin';
  return t.replace(/[^\w.\-()+ ]+/g, '_').slice(0, 180);
}
function extLower(name) {
  const n = s(name).toLowerCase();
  const m = n.match(/(\.[a-z0-9.]+)$/i);
  return m ? m[1] : '';
}

// normalize file_id (strip ?size=...)
function normalizeFileId(raw) {
  const t = s(raw).trim();
  if (!t) return '';
  const q = t.indexOf('?');
  return q >= 0 ? t.slice(0, q) : t;
}

function safeHeadText(buf, n = 160) {
  const b = Buffer.isBuffer(buf) ? buf : Buffer.from(String(buf || ''), 'utf8');
  return b.slice(0, n).toString('utf8').replace(/[^\x09\x0a\x0d\x20-\x7e]+/g, '.');
}
function pushTry(debug, row) {
  if (!debug || !Array.isArray(debug.getFileTries)) return;
  const next = { ...row };
  if (next.bodyHead) next.bodyHead = safeHeadText(next.bodyHead, 120);
  debug.getFileTries.push(next);
  if (debug.getFileTries.length > DEBUG_MAX_TRIES) debug.getFileTries.shift();
}

function httpRequestBuffer(urlString, opts = {}, bodyBuf = null) {
  return new Promise((resolve, reject) => {
    const req = https.request(urlString, opts, (res) => {
      const chunks = [];
      res.on('data', (d) => chunks.push(d));
      res.on('end', () => resolve({
        status: res.statusCode || 0,
        headers: res.headers || {},
        body: Buffer.concat(chunks),
      }));
    });
    req.on('error', reject);
    if (bodyBuf) req.write(bodyBuf);
    req.end();
  });
}

// ---------------- UTF detection + binary heuristics ----------------

function looksLikeUtf16ByBom(buf) {
  if (!buf || buf.length < 2) return null;
  const b0 = buf[0], b1 = buf[1];
  if (b0 === 0xff && b1 === 0xfe) return 'utf16le';
  if (b0 === 0xfe && b1 === 0xff) return 'utf16be';
  return null;
}

function looksLikeUtf8Bom(buf) {
  return !!(buf && buf.length >= 3 && buf[0] === 0xef && buf[1] === 0xbb && buf[2] === 0xbf);
}

// Heuristic: if many NUL bytes and they are mostly on even OR mostly on odd positions => likely UTF-16 without BOM.
function guessUtf16ByNulPattern(buf, sampleBytes = 65536) {
  if (!buf || buf.length < 8) return null;
  const n = Math.min(buf.length, sampleBytes);
  let zeros = 0, zerosEven = 0, zerosOdd = 0;

  for (let i = 0; i < n; i++) {
    if (buf[i] === 0x00) {
      zeros++;
      if ((i & 1) === 0) zerosEven++; else zerosOdd++;
    }
  }

  if (zeros < 64) return null; // not enough zeros to be utf16-ish

  const zRatio = zeros / n;
  const evenShare = zerosEven / zeros;
  const oddShare = zerosOdd / zeros;

  // Require both: many zeros overall AND skew to one parity
  if (zRatio >= 0.08 && (evenShare >= 0.70 || oddShare >= 0.70)) {
    // In UTF-16LE for ASCII-heavy text: odd bytes often 0x00 (low byte has ASCII, high byte 0)
    // In UTF-16BE for ASCII-heavy text: even bytes often 0x00
    return (oddShare >= 0.70) ? 'utf16le' : 'utf16be';
  }

  return null;
}

// Decide if file is binary:
// - allow UTF-16 (BOM or pattern)
// - otherwise if it has lots of control bytes / low printable ratio => binary
function isProbablyBinary(buf) {
  if (!buf || !buf.length) return true;

  const bom16 = looksLikeUtf16ByBom(buf);
  if (bom16) return false;

  const guess16 = guessUtf16ByNulPattern(buf);
  if (guess16) return false; // treat as text

  // Sample-based printable heuristic
  const n = Math.min(buf.length, 65536);
  let bad = 0;
  for (let i = 0; i < n; i++) {
    const c = buf[i];
    // allow: tab(9), lf(10), cr(13)
    if (c === 9 || c === 10 || c === 13) continue;
    // allow standard printable ASCII
    if (c >= 32 && c <= 126) continue;
    // allow some common UTF-8 bytes (>=0xC0) without counting them as "bad"
    if (c >= 0xC0) continue;
    // NUL is strong binary signal when NOT utf16-ish
    if (c === 0x00) { bad += 4; continue; }
    // other control bytes
    if (c < 32) { bad += 1; continue; }
    // 0x7F..0xBF (continuation bytes etc): mildly bad
    if (c >= 0x7F && c <= 0xBF) { bad += 1; continue; }
  }

  // If "badness" too high => binary
  const badRatio = bad / n;
  return badRatio > 0.35;
}

function decodeSmart(buf) {
  if (!buf || !buf.length) return '';

  // UTF-16 by BOM
  const bom16 = looksLikeUtf16ByBom(buf);
  if (bom16 === 'utf16le') {
    try { return buf.slice(2).toString('utf16le'); } catch {}
  }
  if (bom16 === 'utf16be') {
    try {
      // Node doesn't support utf16be directly; swap then decode as le
      const b = Buffer.from(buf.slice(2));
      b.swap16();
      return b.toString('utf16le');
    } catch {}
  }

  // UTF-8 BOM
  if (looksLikeUtf8Bom(buf)) {
    try { return buf.slice(3).toString('utf8'); } catch {}
  }

  // UTF-16 by NUL pattern
  const guess16 = guessUtf16ByNulPattern(buf);
  if (guess16 === 'utf16le') {
    try { return buf.toString('utf16le'); } catch {}
  }
  if (guess16 === 'utf16be') {
    try {
      const b = Buffer.from(buf);
      b.swap16();
      return b.toString('utf16le');
    } catch {}
  }

  // Fallback UTF-8 then latin1
  try { return buf.toString('utf8'); } catch {}
  try { return buf.toString('latin1'); } catch {}
  return '';
}

// ---------------- Yandex getFile (LOGPARSER TOKEN ONLY) ----------------

async function yandexGetFileBinary(fileId, debug) {
  const token = s(env.YANDEX_BOT_TOKEN_LOGPARSER).trim();
  if (!token) throw new Error('Не настроен токен: заполните YANDEX_BOT_TOKEN_LOGPARSER');
  debug.tokenCandidates = ['YANDEX_BOT_TOKEN_LOGPARSER'];

  const fid = normalizeFileId(fileId);
  debug.file_id_raw = s(fileId);
  debug.file_id_norm = fid;
  if (!fid) throw new Error('Empty file_id after normalize');

  const endpoints = [
    {
      kind: 'files',
      post: 'https://botapi.messenger.yandex.net/bot/v1/files/getFile/',
      getBase: 'https://botapi.messenger.yandex.net/bot/v1/files/getFile',
    },
    {
      kind: 'messages',
      post: 'https://botapi.messenger.yandex.net/bot/v1/messages/getFile/',
      getBase: 'https://botapi.messenger.yandex.net/bot/v1/messages/getFile',
    },
  ];

  let lastErr = '';

  const tryDirectBody = (resp, epKind, stepTag) => {
    if (!(resp.status >= 200 && resp.status < 300)) return null;
    const ct = String(resp.headers?.['content-type'] || '').toLowerCase();
    const body = resp.body || Buffer.alloc(0);

    const looksJson = ct.includes('application/json') || (body.length && body[0] === 0x7b);
    if (looksJson) {
      let obj = null;
      try { obj = JSON.parse(body.toString('utf8')); } catch {}
      if (obj && (obj.ok === false || obj.error || obj.description || obj.message)) {
        const errText = String(obj.description || obj.message || obj.error || 'json error');
        lastErr = `${epKind} ${stepTag}: ${errText}`;
        pushTry(debug, { step: `${stepTag}_json_error`, token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: epKind, err: errText });
        return null;
      }
      return null;
    }

    if (body.length > 0) return body;
    lastErr = `${epKind} ${stepTag}: empty body`;
    return null;
  };

  for (const ep of endpoints) {
    // POST {file_id}
    {
      const payload = Buffer.from(JSON.stringify({ file_id: fid }), 'utf8');
      let r1;
      try {
        r1 = await httpRequestBuffer(ep.post, {
          method: 'POST',
          headers: {
            'Authorization': `OAuth ${token}`,
            'Content-Type': 'application/json',
            'Content-Length': payload.length,
          },
        }, payload);
      } catch (e) {
        lastErr = e?.message || String(e);
        pushTry(debug, { step: 'post_exc', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: ep.post, err: lastErr });
        r1 = null;
      }

      if (r1) {
        const bodyText = r1.body ? r1.body.toString('utf8') : '';
        pushTry(debug, { step: 'post', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: ep.post, status: r1.status, bodyHead: bodyText });

        const direct = tryDirectBody(r1, ep.kind, 'post');
        if (direct) return direct;

        if (ep.kind === 'files' && r1.status >= 200 && r1.status < 300) {
          let obj = {};
          try { obj = JSON.parse(bodyText || '{}'); } catch {}
          const url = obj.url || obj.file_url || obj.download_url;
          if (url) {
            const r2 = await httpRequestBuffer(url, { method: 'GET' }, null);
            pushTry(debug, { step: 'files_url_get', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, status: r2.status });
            if (r2.status >= 200 && r2.status < 300 && (r2.body || Buffer.alloc(0)).length) return r2.body;
            lastErr = `download failed: HTTP ${r2.status}`;
          } else {
            lastErr = `files post HTTP ${r1.status}: empty download url`;
          }
        } else if (!(r1.status >= 200 && r1.status < 300)) {
          lastErr = `${ep.kind} post HTTP ${r1.status}`;
        }
      }
    }

    // GET ?file_id=
    {
      const url = `${ep.getBase}${ep.getBase.endsWith('/') ? '' : '/'}?file_id=${encodeURIComponent(fid)}`;
      let rG;
      try {
        rG = await httpRequestBuffer(url, { method: 'GET', headers: { 'Authorization': `OAuth ${token}` } }, null);
      } catch (e) {
        lastErr = e?.message || String(e);
        pushTry(debug, { step: 'get_exc', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: url, err: lastErr });
        rG = null;
      }

      if (rG) {
        const bodyText = rG.body ? rG.body.toString('utf8') : '';
        pushTry(debug, { step: 'getFile_get', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: url, status: rG.status, bodyHead: bodyText });

        const direct = tryDirectBody(rG, ep.kind, 'get');
        if (direct) return direct;

        if (ep.kind === 'files' && rG.status >= 200 && rG.status < 300) {
          let obj = {};
          try { obj = JSON.parse(bodyText || '{}'); } catch {}
          const dl = obj.url || obj.file_url || obj.download_url;
          if (dl) {
            const r2 = await httpRequestBuffer(dl, { method: 'GET' }, null);
            pushTry(debug, { step: 'files_url_get2', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, status: r2.status });
            if (r2.status >= 200 && r2.status < 300 && (r2.body || Buffer.alloc(0)).length) return r2.body;
            lastErr = `download failed: HTTP ${r2.status}`;
          } else {
            lastErr = `files get HTTP ${rG.status}: empty download url`;
          }
        } else if (!(rG.status >= 200 && rG.status < 300)) {
          lastErr = `${ep.kind} get HTTP ${rG.status}`;
        }
      }
    }
  }

  const triesSummary = (debug.getFileTries || [])
    .map(t => `${t.token || 'n/a'}:${t.endpoint || 'n/a'}:${t.step}:${t.status || t.err || 'n/a'}`)
    .slice(-12)
    .join(' | ');

  throw new Error(
    `Не удалось скачать архив из чата (file_id недоступен для YANDEX_BOT_TOKEN_LOGPARSER). ` +
    `${lastErr ? 'Последняя ошибка: ' + lastErr + '. ' : ''}` +
    `${triesSummary ? 'Трейс: ' + triesSummary : ''}`
  );
}

// ---------------- extraction helpers ----------------

function runCmd(cmd, args) {
  child_process.execFileSync(cmd, args, { stdio: ['ignore', 'ignore', 'ignore'] });
}
function isZip(p) {
  const b = fs.readFileSync(p);
  return b.length > 4 && b[0] === 0x50 && b[1] === 0x4b; // PK
}
function isGzip(p) {
  const b = fs.readFileSync(p);
  return b.length > 2 && b[0] === 0x1f && b[1] === 0x8b;
}
function isTar(p) {
  const b = fs.readFileSync(p);
  if (b.length < 265) return false;
  return b.slice(257, 262).toString('utf8') === 'ustar';
}
function extractOne(fileAbs, targetDir, warnings) {
  const name = path.basename(fileAbs).toLowerCase();
  const ext = extLower(name);
  try {
    if (ext === '.zip' || isZip(fileAbs)) { ensureDir(targetDir); runCmd('unzip', ['-o', '-qq', fileAbs, '-d', targetDir]); return true; }
    if (ext === '.tgz' || ext === '.tar.gz' || (isGzip(fileAbs) && name.includes('.tar'))) { ensureDir(targetDir); runCmd('tar', ['-xzf', fileAbs, '-C', targetDir]); return true; }
    if (ext === '.tar' || isTar(fileAbs)) { ensureDir(targetDir); runCmd('tar', ['-xf', fileAbs, '-C', targetDir]); return true; }
    if (ext === '.gz' || isGzip(fileAbs)) {
      ensureDir(targetDir);
      const outName = path.basename(fileAbs).replace(/\.gz$/i, '') || 'gunzipped';
      fs.writeFileSync(path.join(targetDir, outName), zlib.gunzipSync(fs.readFileSync(fileAbs)));
      return true;
    }
  } catch (e) {
    warnings.push(`extract failed: ${path.basename(fileAbs)}: ${e?.message || String(e)}`);
    return false;
  }
  return false;
}
function listFilesRecursive(rootDir, maxFiles) {
  const out = [];
  const q = [rootDir];
  while (q.length) {
    const d = q.shift();
    let items = [];
    try { items = fs.readdirSync(d, { withFileTypes: true }); } catch { continue; }
    for (const it of items) {
      const abs = path.join(d, it.name);
      if (it.isDirectory()) q.push(abs);
      else out.push(abs);
      if (out.length >= maxFiles) return out;
    }
  }
  return out;
}

function appendBlock(fd, header, text) {
  fs.writeSync(fd, `${header}\n`);
  fs.writeSync(fd, text);
  if (!text.endsWith('\n')) fs.writeSync(fd, '\n');
  fs.writeSync(fd, '\n');
}

function buildCombinedToFile(filesAbs, rootAbs, warnings, outPath) {
  const fd = fs.openSync(outPath, 'w');
  let writtenFiles = 0;
  let skippedBinary = 0;

  try {
    for (const abs of filesAbs) {
      let st; try { st = fs.statSync(abs); } catch { continue; }
      if (!st.isFile() || st.size <= 0) continue;

      let buf;
      try { buf = fs.readFileSync(abs); }
      catch (e) { warnings.push(`read failed: ${abs}: ${e?.message || String(e)}`); continue; }

      if (isProbablyBinary(buf)) {
        skippedBinary++;
        continue;
      }

      const text = decodeSmart(buf);
      if (!text.trim()) continue;

      const rel = path.relative(rootAbs, abs);
      appendBlock(fd, `===== FILE: ${rel} (size=${st.size}) =====`, text);
      writtenFiles += 1;
    }
  } finally {
    fs.closeSync(fd);
  }

  const bytesOnDisk = (() => { try { return fs.statSync(outPath).size; } catch { return 0; } })();
  if (skippedBinary > 0) warnings.push(`skipped_as_binary=${skippedBinary} (heuristic)`);

  return { writtenFiles, bytesOnDisk };
}

// ---------------- main ----------------

async function main() {
  ensureDir(DL_DIR);
  ensureDir(EX_DIR);
  ensureDir(OUT_ROOT);

  const debug = { runId, getFileTries: [], warnings: [] };

  let files = base.files;
  if (typeof files === 'string') { try { files = JSON.parse(files); } catch { files = null; } }
  if (!Array.isArray(files)) files = [];

  const nonImage = files.filter(f => String(f?.kind || '').toLowerCase() !== 'image');
  if (!nonImage.length) throw new Error('Во входящем сообщении нет не-графических вложений для разбора.');

  // choose largest attachment
  const pick = nonImage.slice().sort((a, b) => Number(b.size || 0) - Number(a.size || 0))[0] || nonImage[0];

  const sourceFileIdRaw = s(pick.file_id || pick.id);
  const sourceFileId = normalizeFileId(sourceFileIdRaw);
  const sourceFileName = safeName(pick.name || 'attachment.bin');
  if (!sourceFileId) throw new Error('Не удалось определить file_id вложения. Переотправьте архив одним файлом.');

  const dlPath = path.join(DL_DIR, sourceFileName);
  const bin = await yandexGetFileBinary(sourceFileId, debug);
  fs.writeFileSync(dlPath, bin);

  // BFS extraction (nested)
  const q = [{ abs: dlPath, depth: 0, parent: EX_DIR }];
  const visited = new Set();
  const extractedRoots = new Set();

  while (q.length) {
    const cur = q.shift();
    if (!cur || !cur.abs) continue;
    if (visited.has(cur.abs)) continue;
    visited.add(cur.abs);
    if (cur.depth > MAX_DEPTH) continue;

    const target = path.join(cur.parent, safeName(path.basename(cur.abs)) + '_dir');
    const ok = extractOne(cur.abs, target, debug.warnings);
    if (ok) {
      extractedRoots.add(target);
      const filesAbs = listFilesRecursive(target, MAX_FILES);
      for (const f of filesAbs) if (cur.depth + 1 <= MAX_DEPTH) q.push({ abs: f, depth: cur.depth + 1, parent: target });
    }
  }

  let allFiles = [];
  if (extractedRoots.size) {
    for (const r of extractedRoots) allFiles = allFiles.concat(listFilesRecursive(r, MAX_FILES));
  } else {
    allFiles = [dlPath];
  }

  const outDir = path.join(OUT_ROOT, crypto.createHash('sha1').update(runId).digest('hex').slice(0, 16));
  ensureDir(outDir);

  const archiveBase = safeName((base.archiveName || base.sourceFileName || sourceFileName).replace(/\.(zip|tgz|tar\.gz|gz|tar|7z)$/i, '')) || 'combined';
  const combinedName = `${archiveBase}.txt`;
  const combinedPath = path.join(outDir, combinedName);

  const rootAbs = extractedRoots.size ? Array.from(extractedRoots)[0] : DL_DIR;
  const stats = buildCombinedToFile(allFiles, rootAbs, debug.warnings, combinedPath);

  // Identify evidence = full combined (no head/tail)
  const identifyEvidenceName = `${archiveBase}__identify_evidence.txt`;
  const identifyEvidencePath = path.join(outDir, identifyEvidenceName);
  try { fs.linkSync(combinedPath, identifyEvidencePath); }
  catch { fs.copyFileSync(combinedPath, identifyEvidencePath); }

  return [{
    json: {
      ...base,
      _collector_ok: true,
      _collector_error: '',
      _collector_sourceFileId: sourceFileId,
      _collector_sourceFileName: sourceFileName,

      _collector_debug: {
        runId,
        warnings: debug.warnings.slice(0, 80),
        extracted_roots: Array.from(extractedRoots).slice(0, 5),
        combined_written_files: stats.writtenFiles,
      },

      combinedLogPath: combinedPath,
      combinedLogName: combinedName,
      combinedLogBytesWritten: stats.bytesOnDisk,

      // IMPORTANT: NO logsCombined / combinedLogs here
      identify_evidence_path: identifyEvidencePath,
      identify_evidence_name: identifyEvidenceName,
      identify_evidence_text: '',
      identify_evidence_len: 0,
    }
  }];
}

try {
  return await main();
} catch (e) {
  return [{
    json: {
      ...base,
      _collector_ok: false,
      _collector_error: String(e?.message || e),
      _collector_debug: { runId },
      combinedLogPath: '',
      combinedLogName: '',
      combinedLogBytesWritten: 0,
      identify_evidence_path: '',
      identify_evidence_name: '',
      identify_evidence_text: '',
      identify_evidence_len: 0,
    }
  }];
}

/**
 * Klass Missing Reply — FULL REPLACE v1.1
 * Use case:
 *  - Put this node on the FALSE branch of your existing "If Klass" node
 *  - Connect output directly to SendText
 *  - Sends short fallback text with what LLM1 identified (even if Class is missing)
 *
 * Output text format:
 * Название файла: ...
 * Class: ...
 * Model: ...
 * Vendor: ...
 */

const base = $json || {};

// ---------- helpers ----------
const s = (v) => (v === undefined || v === null) ? '' : String(v);
const isObj = (v) => v && typeof v === 'object' && !Array.isArray(v);

function safeJsonParse(v) {
  if (typeof v !== 'string') return null;
  const t = v.trim();
  if (!t) return null;
  // parse only obvious JSON to avoid noise
  if (!(t.startsWith('{') || t.startsWith('['))) return null;
  try { return JSON.parse(t); } catch { return null; }
}

function normalizeKey(k) {
  return String(k || '')
    .toLowerCase()
    .replace(/[^a-z0-9а-яё]/gi, ''); // keep ru/en letters+digits
}

function deepFindFirst(obj, wantedNormKeys, maxDepth = 5) {
  const seen = new Set();

  function walk(node, depth) {
    if (node === null || node === undefined) return '';
    if (depth < 0) return '';

    // primitive
    if (typeof node !== 'object') return '';

    if (seen.has(node)) return '';
    seen.add(node);

    // direct keys first (best match)
    for (const [k, v] of Object.entries(node)) {
      const nk = normalizeKey(k);
      if (wantedNormKeys.has(nk)) {
        const val = s(v).trim();
        if (val) return val;
      }
    }

    // then recurse
    for (const [k, v] of Object.entries(node)) {
      if (v === null || v === undefined) continue;

      // parse embedded JSON strings if present
      if (typeof v === 'string') {
        const parsed = safeJsonParse(v);
        if (parsed) {
          const hit = walk(parsed, depth - 1);
          if (hit) return hit;
        }
        continue;
      }

      if (typeof v === 'object') {
        const hit = walk(v, depth - 1);
        if (hit) return hit;
      }
    }

    return '';
  }

  return walk(obj, maxDepth);
}

function pickField(baseObj, aliases) {
  const wanted = new Set(aliases.map(normalizeKey));

  // 1) direct / deep lookup in base
  let val = deepFindFirst(baseObj, wanted, 6);
  if (val) return val;

  // 2) probe common LLM1 containers explicitly (objects and JSON strings)
  const extraContainers = [
    baseObj.identify,
    baseObj.identify_json,
    baseObj.identify_result,
    baseObj.identifyParsed,
    baseObj.parsed_identify,
    baseObj.parsedIdentify,
    baseObj.llm1,
    baseObj.llm1_result,
    baseObj.llm1_json,
    baseObj.ollama_identify,
    baseObj.ollama,
    baseObj.result,
    baseObj.data,
    baseObj.hw,
  ];

  for (const c of extraContainers) {
    const parsed = isObj(c) ? c : safeJsonParse(c);
    if (!parsed) continue;
    val = deepFindFirst(parsed, wanted, 6);
    if (val) return val;
  }

  return '';
}

function firstNonImageFileNameFromFiles(baseObj) {
  let files = baseObj.files;

  if (typeof files === 'string') {
    const parsed = safeJsonParse(files);
    if (Array.isArray(parsed)) files = parsed;
  }

  if (!Array.isArray(files)) return '';

  // Prefer non-image attachment, fallback to any with name
  const nonImage = files.find(f => {
    const kind = s(f?.kind).toLowerCase();
    const name = s(f?.name || f?.fileName || f?.filename).trim();
    return name && kind !== 'image';
  });
  if (nonImage) return s(nonImage.name || nonImage.fileName || nonImage.filename).trim();

  const any = files.find(f => s(f?.name || f?.fileName || f?.filename).trim());
  return any ? s(any.name || any.fileName || any.filename).trim() : '';
}

function normalizeChatIdForSend(chatIdRaw) {
  const v = s(chatIdRaw).trim();
  if (!v) return '';

  // If already in Yandex format 0/0/<id>, keep as is
  if (/^\d+\/\d+\/.+$/.test(v)) return v;

  // If it's plain id, convert to Yandex SendText-safe chat_id
  return `0/0/${v}`;
}

// ---------- extract routing fields ----------
const chatIdPlain =
  s(base.chatId || base.chat_id_plain || base.ChatID || base.chat || base.fromChatId).trim() ||
  // if chat_id came already as 0/0/<id>, also derive plain chatId for compatibility
  (() => {
    const raw = s(base.chat_id).trim();
    const m = raw.match(/^\d+\/\d+\/(.+)$/);
    return m ? m[1] : '';
  })();

const login = s(base.login || base.userLogin || base.fromLogin).trim();

// ---------- extract identify fields ----------
const vendor = (
  pickField(base, [
    'hw_vendor', 'vendor', 'vendorDetected', 'detected_vendor', 'vendor_name'
  ]) || 'N/A'
).trim();

const model = (
  pickField(base, [
    'hw_model', 'modelDetected', 'model', 'model_name', 'detected_model'
  ]) || 'N/A'
).trim();

const klass = (
  pickField(base, [
    'hw_class', 'klass', 'class', 'classDetected', 'detected_class'
  ]) || 'N/A'
).trim();

// ---------- extract file name ----------
const fileName = (
  pickField(base, [
    'sourceFileName', 'archiveName', 'fileName', 'filename', 'name',
    'source_file_name', 'archive_name', 'mainFileName', 'pickedFileName'
  ]) ||
  firstNonImageFileNameFromFiles(base) ||
  'N/A'
).trim();

// ---------- build reply ----------
const text =
  `Название файла: ${fileName}\n` +
  `Class: ${klass}\n` +
  `Model: ${model}\n` +
  `Vendor: ${vendor}`;

// ---------- output ----------
const chat_id = normalizeChatIdForSend(base.chat_id || chatIdPlain);

return [{
  json: {
    ...base,

    // For SendText node compatibility (keep both styles)
    chatId: chatIdPlain || s(base.chatId).trim(),
    chat_id: chat_id || s(base.chat_id).trim(),
    login,

    text,
  }
}];
